export const SOLIDITY_CONTRACT_CODE = `
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

/**
 * @title AnonymousFacultyFeedback
 * @dev Implements a double-blind token system for anonymous feedback submission
 */
contract AnonymousFacultyFeedback {
    struct Feedback {
        bytes32 encryptedData; // Asymmetric encryption hash
        uint256 timestamp;
        string facultyId;
        string subjectId;
    }

    // Mapping of used tokens to prevent double voting
    mapping(bytes32 => bool) public usedTokens;

    // Aggregated scores per subject-faculty pair
    // SubjectID => FacultyID => TotalScore
    mapping(string => mapping(string => uint256)) private totalScores;
    mapping(string => mapping(string => uint256)) private count;

    event FeedbackSubmitted(string facultyId, string subjectId, uint256 timestamp);

    /**
     * @dev Validates token via off-chain Ring Signature or Blind Signature
     * and records the feedback anonymously.
     */
    function submitFeedback(
        bytes32 token, 
        bytes32 encryptedData, 
        string memory facultyId, 
        string memory subjectId,
        uint256 scoreSum // Pre-calculated sum for low-gas aggregation
    ) public {
        require(!usedTokens[token], "Token already used");

        usedTokens[token] = true;
        totalScores[subjectId][facultyId] += scoreSum;
        count[subjectId][facultyId] += 1;

        emit FeedbackSubmitted(facultyId, subjectId, block.timestamp);
    }

    function getAveragePoints(string memory subjectId, string memory facultyId) 
        public view returns (uint256) 
    {
        if (count[subjectId][facultyId] == 0) return 0;
        return (totalScores[subjectId][facultyId] * 100) / (count[subjectId][facultyId] * 10);
    }
}
`;

import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, 
  FileText, 
  ShieldCheck, 
  BarChart3, 
  Settings, 
  UserCircle,
  AlertCircle,
  Database,
  Lock,
  Code
} from 'lucide-react';
import Dashboard from './components/Dashboard';
import FeedbackPortal from './components/FeedbackPortal';
import AnalysisView from './components/AnalysisView';
import TechnicalRoadmap from './components/TechnicalRoadmap';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import { FeedbackEntry } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'feedback' | 'analysis' | 'roadmap'>('dashboard');
  const [feedbacks, setFeedbacks] = useState<FeedbackEntry[]>([]);
  const [isSidebarOpen, setSidebarOpen] = useState(true);

  const addFeedback = (entry: FeedbackEntry) => {
    setFeedbacks(prev => [...prev, entry]);
  };

  const tabs = [
    { id: 'dashboard', label: 'Overview', icon: LayoutDashboard },
    { id: 'feedback', label: 'Submit Feedback', icon: FileText },
    { id: 'analysis', label: 'HOD Analysis', icon: BarChart3 },
    { id: 'roadmap', label: 'Architecture', icon: Code },
  ];

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {/* Sidebar */}
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        tabs={tabs} 
        isOpen={isSidebarOpen}
        toggleSidebar={() => setSidebarOpen(!isSidebarOpen)}
      />

      {/* Main Content */}
      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <Header activeTab={tabs.find(t => t.id === activeTab)?.label || 'SRK-IT'} />

        <main className="flex-1 overflow-y-auto p-4 md:p-8">
          <div className="max-w-7xl mx-auto space-y-6">
            {activeTab === 'dashboard' && <Dashboard feedbacks={feedbacks} />}
            {activeTab === 'feedback' && <FeedbackPortal onSubmit={addFeedback} />}
            {activeTab === 'analysis' && <AnalysisView feedbacks={feedbacks} />}
            {activeTab === 'roadmap' && <TechnicalRoadmap />}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

