import React, { useState } from 'react';
import { 
  FileText, 
  BarChart3, 
  Code,
  Lock,
  UserCheck
} from 'lucide-react';
import FeedbackPortal from './components/FeedbackPortal';
import AnalysisView from './components/AnalysisView';
import TechnicalRoadmap from './components/TechnicalRoadmap';
import AdminDashboard from './components/AdminDashboard';
import FacultyResultsView from './components/FacultyResultsView';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Auth from './components/Auth';
import { FeedbackEntry, User, UserRole, Subject, Faculty, Department } from './types';
import { 
  SUBJECTS as INITIAL_SUBJECTS, 
  FACULTY_DATA as INITIAL_FACULTIES,
  THEORY_METRICS as INITIAL_THEORY_METRICS,
  LAB_METRICS as INITIAL_LAB_METRICS,
  DEPARTMENTS,
  SEMESTERS
} from './constants';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<'feedback' | 'analysis' | 'roadmap' | 'admin' | 'faculty_results'>('feedback');
  const [feedbacks, setFeedbacks] = useState<FeedbackEntry[]>([]);
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [isGlobalSessionActive, setIsGlobalSessionActive] = useState(true);

  const [subjects, setSubjects] = useState<Subject[]>(INITIAL_SUBJECTS);
  const [faculties, setFaculties] = useState<Faculty[]>(INITIAL_FACULTIES);

  const [theoryQuestions, setTheoryQuestions] = useState<Record<Department, string[]>>(
    DEPARTMENTS.reduce((acc, dept) => ({ ...acc, [dept]: [...INITIAL_THEORY_METRICS] }), {} as Record<Department, string[]>)
  );
  const [labQuestions, setLabQuestions] = useState<Record<Department, string[]>>(
    DEPARTMENTS.reduce((acc, dept) => ({ ...acc, [dept]: [...INITIAL_LAB_METRICS] }), {} as Record<Department, string[]>)
  );

  const [sessionRegistry, setSessionRegistry] = useState<Record<string, boolean>>(
    DEPARTMENTS.reduce((acc, dept) => {
      SEMESTERS.forEach(sem => {
        acc[`${dept}-${sem}`] = true;
      });
      return acc;
    }, {} as Record<string, boolean>)
  );

  const addFeedback = (entry: FeedbackEntry) => {
    setFeedbacks(prev => [...prev, entry]);
  };

  const handleAuth = (authenticatedUser: User) => {
    setUser(authenticatedUser);
    if (authenticatedUser.role === UserRole.ADMIN) {
      setActiveTab('admin');
    } else if (authenticatedUser.role === UserRole.FACULTY) {
      setActiveTab('faculty_results');
    } else if (authenticatedUser.role === UserRole.VIEWER) {
      setActiveTab('analysis');
    } else {
      setActiveTab('feedback');
    }
  };

  const logout = () => {
    setUser(null);
  };

  if (!user) {
    return <Auth onAuthenticate={handleAuth} />;
  }

  // UPDATED: Strict tab filtering
  const tabs = [
    { id: 'feedback', label: 'Submit Feedback', icon: FileText, roles: [UserRole.STUDENT] },
    { id: 'faculty_results', label: 'My Results', icon: UserCheck, roles: [UserRole.FACULTY] },
    { id: 'analysis', label: 'HOD Analysis', icon: BarChart3, roles: [UserRole.ADMIN, UserRole.VIEWER] },
    { id: 'admin', label: 'Admin Power', icon: Lock, roles: [UserRole.ADMIN] }, // Only Chief Admin
    { id: 'roadmap', label: 'Architecture', icon: Code },
  ].filter(tab => !tab.roles || tab.roles.includes(user.role));

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        tabs={tabs} 
        isOpen={isSidebarOpen}
        toggleSidebar={() => setSidebarOpen(!isSidebarOpen)}
        user={user}
        onLogout={logout}
      />

      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <Header 
          activeTab={tabs.find(t => t.id === activeTab)?.label || 'SRK-IT'} 
          user={user}
        />

        <main className="flex-1 overflow-y-auto p-4 md:p-8 bg-[#fdfdfd]">
          <div className="max-w-7xl mx-auto space-y-6">
            {activeTab === 'feedback' && (
              <FeedbackPortal 
                onSubmit={addFeedback} 
                onLogout={logout} 
                user={user} 
                subjects={subjects}
                sessionRegistry={sessionRegistry}
                theoryQuestions={theoryQuestions}
                labQuestions={labQuestions}
                isGlobalSessionActive={isGlobalSessionActive}
              />
            )}
            {activeTab === 'faculty_results' && (
              <FacultyResultsView 
                user={user} 
                feedbacks={feedbacks} 
                faculties={faculties} 
                subjects={subjects}
                theoryQuestions={theoryQuestions}
                labQuestions={labQuestions}
              />
            )}
            {activeTab === 'analysis' && <AnalysisView feedbacks={feedbacks} user={user} />}
            {activeTab === 'admin' && (
              <AdminDashboard 
                subjects={subjects} 
                setSubjects={setSubjects}
                faculties={faculties}
                setFaculties={setFaculties}
                sessionRegistry={sessionRegistry}
                setSessionRegistry={setSessionRegistry}
                theoryQuestions={theoryQuestions}
                setTheoryQuestions={setTheoryQuestions}
                labQuestions={labQuestions}
                setLabQuestions={setLabQuestions}
                isGlobalSessionActive={isGlobalSessionActive}
                setIsGlobalSessionActive={setIsGlobalSessionActive}
              />
            )}
            {activeTab === 'roadmap' && <TechnicalRoadmap />}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

