const GOOGLE_CLIENT_ID = "642029720812-i7s7uba0d4csckjr67ug489u4deci2ok.apps.googleusercontent.com";

// Chief Admin Hardcoded Credentials
const CHIEF_ADMIN = {
  name: "Admin",
  email: "admin.srkit@gmail.com",
  password: "123456"
};

interface AuthProps {
  onAuthenticate: (user: UserType) => void;
}

declare global {
  interface Window {
    google: any;
  }
}

const Auth: React.FC<AuthProps> = ({ onAuthenticate }) => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [isLogin, setIsLogin] = useState(true);
  const [dept, setDept] = useState<Department>('CSE');
  const [sem, setSem] = useState<Semester>('3.1');
  const [error, setError] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    fullName: '',
    identifier: '',
    password: ''
  });

  useEffect(() => {
    const script = document.createElement('script');
    script.src = 'https://accounts.google.com/gsi/client';
    script.async = true;
    script.defer = true;
    document.body.appendChild(script);

    script.onload = () => {
      if (window.google) {
        window.google.accounts.id.initialize({
          client_id: GOOGLE_CLIENT_ID,
          callback: handleGoogleResponse,
        });
      }
    };

    return () => {
      if (document.body.contains(script)) {
        document.body.removeChild(script);
      }
    };
  }, [role]);

  useEffect(() => {
    if (role && isLogin) {
      const btn = document.getElementById('google-login-btn');
      if (btn && window.google) {
        window.google.accounts.id.renderButton(btn, { 
          theme: 'outline', 
          size: 'large', 
          width: '100%', 
          text: 'continue_with', 
          shape: 'pill' 
        });
      }
    }
  }, [role, isLogin]);

  const handleGoogleResponse = (response: any) => {
    try {
      const base64Url = response.credential.split('.')[1];
      const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
      const payload = JSON.parse(window.atob(base64));

      const email = payload.email;

      if (!email.endsWith('@srkit.ac.in') && !email.endsWith('@gmail.com')) {
        setError("Unauthorized domain. Use your academic email.");
        return;
      }

      // Updated Admin/HOD Logic
      if (role === UserRole.ADMIN) {
        // If they are trying to be ADMIN, check Chief Admin credentials
        if (email === CHIEF_ADMIN.email && payload.name === CHIEF_ADMIN.name) {
          onAuthenticate({
            fullName: payload.name,
            email: email,
            role: UserRole.ADMIN,
            department: dept
          });
          return;
        }

        // Otherwise check if they are an HOD (Reassigned to VIEWER)
        const designatedHod = HOD_LIST[dept];
        if (payload.name.toLowerCase().trim() === designatedHod.toLowerCase().trim()) {
          onAuthenticate({
            fullName: payload.name,
            email: email,
            role: UserRole.VIEWER, // Reassigned permission
            department: dept
          });
          return;
        }

        setError("Access Denied: You do not have Administrative or HOD clearance for this node.");
        return;
      }

      onAuthenticate({
        fullName: payload.name,
        email: email,
        role: role!,
        department: dept,
        semester: role === UserRole.STUDENT ? sem : undefined,
        facultyId: role === UserRole.FACULTY ? 'f1' : undefined
      });
    } catch (err) {
      setError("Google authentication failed.");
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    // Manual Credentials Check
    if (role === UserRole.ADMIN) {
      // Check Chief Admin
      if (formData.identifier === CHIEF_ADMIN.email && formData.password === CHIEF_ADMIN.password) {
        onAuthenticate({
          fullName: CHIEF_ADMIN.name,
          email: CHIEF_ADMIN.email,
          role: UserRole.ADMIN,
          department: dept
        });
        return;
      }

      // Check HOD (HODs don't have hardcoded password here, but we check name/ID simulation)
      const designatedHod = HOD_LIST[dept];
      if (formData.fullName.toLowerCase().trim() === designatedHod.toLowerCase().trim()) {
        onAuthenticate({
          fullName: formData.fullName,
          email: formData.identifier,
          role: UserRole.VIEWER, // Reduced permission
          department: dept
        });
        return;
      }

      setError("Invalid Chief Admin credentials or Unauthorized HOD access.");
      return;
    }

    onAuthenticate({
      fullName: formData.fullName,
      email: formData.identifier,
      role: role!,
      department: dept,
      semester: role === UserRole.STUDENT ? sem : undefined,
      facultyId: role === UserRole.FACULTY ? 'f1' : undefined
    });
  };

  const renderRoleSelector = () => (
    <div className="space-y-8 animate-in fade-in zoom-in duration-500 max-w-lg w-full">
