  const facultyRecord = useMemo(() => {
    return faculties.find(f => f.name.includes(user.fullName) || f.id === user.facultyId);
  }, [user, faculties]);

  // Subjects taught by this faculty
  const facultySubjects = useMemo(() => {
    if (!facultyRecord) return [];
    return subjects.filter(s => facultyRecord.subjects.includes(s.id));
  }, [facultyRecord, subjects]);

  // Aggregate simulated data (combined with any real feedbacks)
  const stats = useMemo(() => {
    return facultySubjects.map(sub => {
      const questions = sub.type === FeedbackType.THEORY ? theoryQuestions[sub.department] : labQuestions[sub.department];
      return {
        id: sub.id,
        name: sub.name,
        type: sub.type,
        avgScore: 16.5 + (Math.random() * 3.2), // Adjusted for wider range to trigger insights
        totalResponses: 42 + Math.floor(Math.random() * 10),
        metrics: questions?.map((m, idx) => {
          // Simulation logic: generate some "low" scores to test the feature
          const baseScore = 3.5 + (Math.random() * 1.5);
          // Force lower scores on first few metrics for demonstration if random isn't enough
          const score = idx < 2 ? baseScore - 1.5 : baseScore;
          return {
            label: m,
            score: Math.max(1, Math.min(5, score))
          };
        }) || []
      };
    });
  }, [facultySubjects, theoryQuestions, labQuestions]);

  // NEW: Performance Insights Logic
  const insights = useMemo(() => {
    const allMetrics = stats.flatMap(s => s.metrics.map(m => ({ ...m, subject: s.name })));

    // Areas for Improvement: Metrics < 3.0
    const improvements = allMetrics
      .filter(m => m.score < 3.0)
      .sort((a, b) => a.score - b.score)
      .slice(0, 3);

    return improvements;
  }, [stats]);

  const overallAvg = useMemo(() => {
    if (stats.length === 0) return 0;
    return stats.reduce((acc, s) => acc + s.avgScore, 0) / stats.length;
  }, [stats]);

  const chartData = useMemo(() => {
    return stats.map(s => ({
      name: s.id,
      score: parseFloat(s.avgScore.toFixed(2))
    }));
  }, [stats]);

  const activeStats = useMemo(() => {
    if (selectedSubject === 'all') return null;
    return stats.find(s => s.id === selectedSubject);
