const GOOGLE_CLIENT_ID = "642029720812-i7s7uba0d4csckjr67ug489u4deci2ok.apps.googleusercontent.com";

// Hardcoded Chief Admin Credentials
const CHIEF_ADMIN = {
  name: "Admin",
  email: "admin.srkit@gmail.com",
  password: "123456"
};

interface AuthProps {
  onAuthenticate: (user: UserType) => void;
}

declare global {
  interface Window {
    google: any;
  }
}

const Auth: React.FC<AuthProps> = ({ onAuthenticate }) => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [isLogin, setIsLogin] = useState(true);
  const [dept, setDept] = useState<Department>('CSE');
  const [sem, setSem] = useState<Semester>('3.1');
  const [error, setError] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    fullName: '',
    identifier: '',
    password: ''
  });

  useEffect(() => {
    const script = document.createElement('script');
    script.src = 'https://accounts.google.com/gsi/client';
    script.async = true;
    script.defer = true;
    document.body.appendChild(script);

    script.onload = () => {
      if (window.google) {
        window.google.accounts.id.initialize({
          client_id: GOOGLE_CLIENT_ID,
          callback: handleGoogleResponse,
        });
      }
    };

    return () => {
      if (document.body.contains(script)) {
        document.body.removeChild(script);
      }
    };
  }, [role]);

  const handleGoogleResponse = (response: any) => {
    try {
      const base64Url = response.credential.split('.')[1];
      const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
      const payload = JSON.parse(window.atob(base64));

      const email = payload.email;

      // Logic for Admin / HOD role validation
      if (role === UserRole.ADMIN) {
        if (email === CHIEF_ADMIN.email) {
          onAuthenticate({
            fullName: "Chief Admin",
            email: email,
            role: UserRole.ADMIN,
            department: dept
          });
          return;
        }

        // Reassign HODs to VIEWER role
        const designatedHod = HOD_LIST[dept];
        if (payload.name.toLowerCase().includes(designatedHod.toLowerCase())) {
          onAuthenticate({
            fullName: payload.name,
            email: email,
            role: UserRole.VIEWER,
            department: dept
          });
          return;
        }

        setError("Administrative access restricted to authorized Chief Admin.");
        return;
      }

      onAuthenticate({
        fullName: payload.name,
        email: email,
        role: role!,
        department: dept,
        semester: role === UserRole.STUDENT ? sem : undefined,
        facultyId: role === UserRole.FACULTY ? 'F001' : undefined // Simulated
      });
    } catch (err) {
      setError("Google authentication failed.");
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    // Strict Chief Admin Validation
    if (role === UserRole.ADMIN) {
      if (formData.identifier === CHIEF_ADMIN.email && formData.password === CHIEF_ADMIN.password) {
        onAuthenticate({
          fullName: CHIEF_ADMIN.name,
          email: CHIEF_ADMIN.email,
          role: UserRole.ADMIN,
          department: dept
        });
        return;
      }

      // Check if HOD is logging in (reassigned to VIEWER)
      const designatedHod = HOD_LIST[dept];
      if (formData.fullName.toLowerCase() === designatedHod.toLowerCase()) {
        onAuthenticate({
          fullName: formData.fullName,
          email: formData.identifier,
          role: UserRole.VIEWER,
          department: dept
        });
        return;
      }

      setError("Invalid credentials. Access to Admin Portal is restricted to Chief Admin.");
      return;
    }

    onAuthenticate({
      fullName: formData.fullName,
      email: formData.identifier,
      role: role!,
      department: dept,
      semester: role === UserRole.STUDENT ? sem : undefined,
      facultyId: role === UserRole.FACULTY ? 'F001' : undefined
    });
  };

  const renderRoleSelector = () => (
    <div className="space-y-8 animate-in fade-in zoom-in duration-500 max-w-lg w-full">
      <div className="text-center space-y-4">
        <div className="mx-auto w-20 h-20 bg-blue-600 rounded-[2rem] flex items-center justify-center text-white shadow-2xl mb-6">
          <Shield size={40} />
        </div>
        <h2 className="text-4xl font-black text-slate-900 tracking-tight uppercase">SRK-IT Access</h2>
        <p className="text-slate-500 font-bold uppercase tracking-widest text-xs">Select access level to continue</p>
      </div>

      <div className="grid grid-cols-1 gap-4">
        {[
          { id: UserRole.ADMIN, label: 'Admin / HOD Access', icon: Users, desc: 'Central governance and auditing', color: 'indigo' },
          { id: UserRole.FACULTY, label: 'Faculty Member', icon: Presentation, desc: 'View performance audit results', color: 'emerald' },
          { id: UserRole.STUDENT, label: 'Academic Student', icon: GraduationCap, desc: 'Submit branch-specific feedback', color: 'blue' },
        ].map((r) => (
          <button
            key={r.id}
            onClick={() => { setRole(r.id); setError(null); }}
            className="group flex items-center gap-6 p-6 bg-white border border-slate-200 rounded-[2.5rem] hover:border-blue-600 hover:shadow-2xl transition-all text-left"
          >
            <div className={`w-14 h-14 rounded-2xl bg-${r.color}-50 text-${r.color}-600 flex items-center justify-center shrink-0 group-hover:bg-${r.color}-600 group-hover:text-white transition-all`}>
              <r.icon size={28} />
