              <h3 className="text-lg font-black text-slate-900 uppercase tracking-tight">{r.label}</h3>
              <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mt-1">{r.desc}</p>
            </div>
            <ChevronRight className="text-slate-200 group-hover:text-blue-600 transition-all" size={20} />
          </button>
        ))}
      </div>
    </div>
  );

  const renderAuthForm = () => (
    <div className="space-y-6 animate-in slide-in-from-right duration-500 max-w-md w-full">
      <button 
        onClick={() => { setRole(null); setError(null); }}
        className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest hover:text-blue-600 transition-colors group"
      >
        <ArrowLeft size={14} className="group-hover:-translate-x-1 transition-transform" /> Back
      </button>

      <div className="bg-white p-10 rounded-[3rem] border border-slate-200 shadow-2xl space-y-8">
        <div className="text-center">
          <h2 className="text-2xl font-black text-slate-900 tracking-tight">Node Verification</h2>
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest mt-2">Enter credentials for {role}</p>
        </div>

        {error && (
          <div className="p-4 bg-red-50 border border-red-100 rounded-2xl flex items-center gap-3 text-red-600 text-xs font-bold">
