            />
          </div>

          <button type="submit" className="w-full py-4 bg-slate-900 text-white rounded-xl font-black uppercase tracking-widest text-[10px] shadow-xl hover:bg-black transition-all mt-4">
            Verify Identity
          </button>
        </form>
      </div>
    </div>
  );

  return (
    <div className="flex min-h-screen bg-slate-50">
      <div className="hidden lg:flex w-1/3 bg-slate-900 text-white p-16 flex-col justify-center items-center relative overflow-hidden">
