  }, [user, faculties]);

  // Subjects taught by this faculty
  const facultySubjects = useMemo(() => {
    if (!facultyRecord) return [];
    return subjects.filter(s => facultyRecord.subjects.includes(s.id));
  }, [facultyRecord, subjects]);

  // Threshold for improvement detection
  const IMPROVEMENT_THRESHOLD = 3.0;

  // Aggregate simulated data with improvement logic
  const stats = useMemo(() => {
    return facultySubjects.map(sub => {
      const questions = sub.type === FeedbackType.THEORY ? theoryQuestions[sub.department] : labQuestions[sub.department];
      return {
        id: sub.id,
        name: sub.name,
        type: sub.type,
        avgScore: 16.2 + (Math.random() * 3.5),
        totalResponses: 38 + Math.floor(Math.random() * 15),
        metrics: questions?.map((m, idx) => {
          // Simulation: Ensure some metrics are low to demonstrate the feature
          const base = 3.2 + (Math.random() * 1.5);
          const score = (idx === 0 || idx === 7) ? base - 1.2 : base; // Force some low scores
          return {
            label: m,
            score: Math.max(1, Math.min(5, score))
          };
        }) || []
      };
    });
  }, [facultySubjects, theoryQuestions, labQuestions]);

  // Performance Insights Engine
  const improvementInsights = useMemo(() => {
    const allMetrics = stats.flatMap(s => s.metrics.map(m => ({ ...m, subject: s.name })));

    // Group by metric label to get global average for this faculty member
    const aggregatedMetrics: Record<string, { total: number, count: number }> = {};
    allMetrics.forEach(m => {
      if (!aggregatedMetrics[m.label]) aggregatedMetrics[m.label] = { total: 0, count: 0 };
      aggregatedMetrics[m.label].total += m.score;
      aggregatedMetrics[m.label].count += 1;
    });

    return Object.entries(aggregatedMetrics)
      .map(([label, data]) => ({ label, avg: data.total / data.count }))
      .filter(m => m.avg < IMPROVEMENT_THRESHOLD)
      .sort((a, b) => a.avg - b.avg)
      .slice(0, 3);
  }, [stats]);

  const overallAvg = useMemo(() => {
    if (stats.length === 0) return 0;
    return stats.reduce((acc, s) => acc + s.avgScore, 0) / stats.length;
  }, [stats]);

  const chartData = useMemo(() => {
    return stats.map(s => ({
      name: s.id,
      score: parseFloat(s.avgScore.toFixed(2))
    }));
  }, [stats]);

  const activeStats = useMemo(() => {
    if (selectedSubject === 'all') return null;
    return stats.find(s => s.id === selectedSubject);
  }, [selectedSubject, stats]);

  return (
    <div className="space-y-8 animate-in fade-in duration-700">
      {/* Welcome Header */}
      <div className="bg-slate-900 rounded-[2.5rem] p-10 text-white shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 right-0 p-12 opacity-10">
          <Award size={200} className="text-blue-400" />
        </div>
        <div className="relative z-10 flex flex-col md:flex-row md:items-center justify-between gap-8">
          <div>
            <div className="inline-flex items-center gap-2 px-3 py-1 bg-blue-500/10 border border-blue-500/20 rounded-full text-blue-400 text-[10px] font-black uppercase tracking-[0.2em] mb-4">
              <ShieldCheck size={12} /> Verified Faculty Portal
            </div>
            <h2 className="text-4xl font-black mb-2 tracking-tight">Hello, {user.fullName}</h2>
            <p className="text-slate-400 font-medium">Academic Year 2024-25 Analysis</p>
          </div>
          <div className="flex gap-4">
            <div className="bg-white/5 border border-white/10 p-6 rounded-3xl backdrop-blur-md text-center min-w-[140px]">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Audit Score</p>
              <p className="text-3xl font-black text-blue-400">{overallAvg.toFixed(2)}</p>
            </div>
          </div>
        </div>
      </div>

      {/* Improvement Areas Component */}
      {improvementInsights.length > 0 && (
        <div className="bg-white border-4 border-amber-100 rounded-[2.5rem] p-8 shadow-xl animate-in slide-in-from-top duration-500">
          <div className="flex items-center gap-4 mb-6">
            <div className="p-4 bg-amber-50 text-amber-600 rounded-2xl">
              <Lightbulb size={32} />
            </div>
            <div>
              <h3 className="text-xl font-black text-slate-900 uppercase tracking-tight">Performance Insights</h3>
              <p className="text-slate-500 text-xs font-bold uppercase tracking-widest">Strategic Improvement Areas Flagged by Student Sentiment</p>
            </div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {improvementInsights.map((m, i) => (
              <div key={i} className="bg-amber-50/50 p-6 rounded-3xl border border-amber-100 relative group overflow-hidden">
                <div className="absolute top-0 right-0 p-4 opacity-10">
                  <AlertCircle size={40} className="text-amber-600" />
                </div>
                <p className="text-[9px] font-black text-amber-600 uppercase tracking-widest mb-2 flex items-center gap-1">
                  <TrendingUp size={10} className="rotate-180" /> Priority Adjustment
                </p>
                <h4 className="font-bold text-slate-800 text-sm leading-tight mb-4">{m.label}</h4>
                <div className="flex items-center justify-between">
                  <div className="flex items-baseline gap-1">
                    <span className="text-2xl font-black text-amber-700">{m.avg.toFixed(1)}</span>
                    <span className="text-[9px] font-bold text-amber-500 uppercase">Avg</span>
                  </div>
                  <div className="h-2 w-16 bg-slate-200 rounded-full overflow-hidden">
                    <div className="h-full bg-amber-500" style={{ width: `${(m.avg / 5) * 100}%` }}></div>
                  </div>
                </div>
              </div>
            ))}
          </div>
          <div className="mt-6 flex items-center justify-center gap-2 text-[10px] font-black text-slate-300 uppercase tracking-[0.2em]">
            <Activity size={14} /> Aggregated Statistical Deviation Detected
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm flex flex-col">
          <div className="flex items-center justify-between mb-8">
            <div>
              <h3 className="text-xl font-bold text-slate-900 flex items-center gap-2">
                <BarChart2 className="text-blue-600" /> Course Performance
              </h3>
              <p className="text-xs text-slate-500 font-medium uppercase mt-1">Avg Score per Unit</p>
            </div>
            <select 
              value={selectedSubject} 
              onChange={(e) => setSelectedSubject(e.target.value)}
              className="bg-slate-50 border-2 border-slate-100 rounded-xl px-4 py-2 text-[10px] font-black uppercase outline-none focus:border-blue-600 cursor-pointer"
            >
              <option value="all">All Courses</option>
              {facultySubjects.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
            </select>
          </div>

          <div className="h-[350px] w-full flex-1">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 10, fontWeight: 700}} />
                <YAxis domain={[10, 20]} axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 10, fontWeight: 700}} />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}} 
                  contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)', fontSize: '12px', fontWeight: 'bold'}}
                />
                <Bar dataKey="score" radius={[8, 8, 0, 0]} barSize={50}>
                  {chartData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.score > 18.0 ? '#10b981' : entry.score < 14.5 ? '#f59e0b' : '#3b82f6'} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm flex flex-col">
          <div className="mb-8">
            <h3 className="text-xl font-bold text-slate-900 flex items-center gap-2">
              <Target className="text-blue-600" /> Detail Audit
            </h3>
            <p className="text-xs text-slate-500 font-medium uppercase mt-1">
              {activeStats ? activeStats.name : 'Aggregate Performance'}
            </p>
          </div>

          <div className="space-y-4 flex-1 overflow-y-auto pr-2 custom-scrollbar">
            {(activeStats?.metrics || stats[0]?.metrics || []).map((m, i) => (
              <div key={i} className="space-y-1.5">
                <div className="flex justify-between text-[11px] font-bold text-slate-700">
                  <span className="truncate max-w-[80%]">{m.label}</span>
                  <span className={`${m.score < IMPROVEMENT_THRESHOLD ? 'text-amber-600' : 'text-blue-600'}`}>{(m.score * 4).toFixed(1)}/20</span>
                </div>
                <div className="h-1.5 bg-slate-100 rounded-full overflow-hidden">
                  <div 
                    className={`h-full rounded-full transition-all duration-1000 ${m.score > 4.5 ? 'bg-emerald-500' : m.score < IMPROVEMENT_THRESHOLD ? 'bg-amber-500' : 'bg-blue-500'}`} 
                    style={{ width: `${(m.score / 5) * 100}%` }}
                  ></div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

