// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

/**
 * @dev Simulated import of OpenZeppelin Ownable
 */
abstract contract Ownable {
    address private _owner;
    constructor() { _owner = msg.sender; }
    modifier onlyOwner() { require(_owner == msg.sender, "Caller is not the owner"); _; }
}

/**
 * @title SRKInstituteFeedback
 * @notice Refactored for Single-Point Super-Admin Control
 */
contract SRKInstituteFeedback is Ownable {
    struct FacultyStats {
        uint256 totalScore;
        uint256 responseCount;
        bool sessionActive;
    }

    // Registry: Dept -> Semester -> Subject -> Faculty -> Stats
    mapping(string => mapping(string => mapping(string => mapping(string => FacultyStats)))) private registry;
    mapping(bytes32 => bool) public nullifiers;

    bool public globalSessionActive = true;

    /**
     * @notice Only the Super-Admin (Owner) can toggle global system state
     */
    function toggleGlobalSession(bool status) public onlyOwner {
        globalSessionActive = status;
    }

    /**
     * @notice Anchors feedback to the ledger with ZK-nullifier check
     */
    function submitSecureFeedback(
        bytes32 nullifier, 
        string memory dept,
        string memory sem,
        string memory subjectId,
        string memory facultyId,
        uint256 scoreSum
    ) public {
        require(globalSessionActive, "System is currently locked by Admin");
        require(!nullifiers[nullifier], "Identity already used for this batch");

        nullifiers[nullifier] = true;
        FacultyStats storage stats = registry[dept][sem][subjectId][facultyId];
        stats.totalScore += scoreSum;
        stats.responseCount += 1;
    }

    /**
     * @notice Super-Admin can purge or reset specific nodes
     */
    function resetNode(string memory dept, string memory sem) public onlyOwner {
        // Administrative purge logic
    }
}
`;

