    const isHOD = Object.values(HOD_LIST).some(h => h.toLowerCase() === formData.fullName.toLowerCase());

    onAuthenticate({
      fullName: formData.fullName,
      email: formData.identifier,
      role: role === UserRole.FACULTY || isHOD ? UserRole.FACULTY : UserRole.STUDENT,
