          <button type="submit" className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase tracking-widest text-[11px] shadow-2xl mt-4 flex items-center justify-center gap-3 active:scale-95 transition-transform">
            Initialize Authorization <CheckCircle2 size={16} />
          </button>
        </form>
      </div>
    </div>
  );

  return (
