const SUPER_ADMIN_CREDS = {
  email: "admin@gmail.com",
  password: "123456"
};

interface AuthProps {
  onAuthenticate: (user: UserType) => void;
}

const Auth: React.FC<AuthProps> = ({ onAuthenticate }) => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [dept, setDept] = useState<Department>('CSE');
  const [sem, setSem] = useState<Semester>('3.1');
  const [error, setError] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    fullName: '',
    identifier: '',
    password: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    // 1. Super-Admin Logic
    if (role === UserRole.ADMIN) {
      if (formData.identifier === SUPER_ADMIN_CREDS.email && formData.password === SUPER_ADMIN_CREDS.password) {
        onAuthenticate({
          fullName: "Chief Admin",
          email: SUPER_ADMIN_CREDS.email,
          role: UserRole.ADMIN,
        });
        return;
      }
      setError("Invalid Administrative Credentials.");
      return;
    }

    // 2. Role Determination
    let finalRole = role!;

    // Check if identifying as an HOD
    const isHOD = Object.values(HOD_LIST).some(h => h.toLowerCase().trim() === formData.fullName.toLowerCase().trim());
    if (isHOD) {
      finalRole = UserRole.HOD;
    }

    onAuthenticate({
      fullName: formData.fullName,
      email: formData.identifier,
      role: finalRole,
      department: dept,
      semester: finalRole === UserRole.STUDENT ? sem : undefined,
      facultyId: finalRole === UserRole.FACULTY ? 'F001' : undefined
