      <div className="grid grid-cols-1 gap-4">
        {[
          { id: UserRole.ADMIN, label: 'Central Admin', icon: LockKeyhole, desc: 'Master Governance Node', color: 'indigo' },
          { id: UserRole.FACULTY, label: 'Faculty / HOD Portal', icon: Presentation, desc: 'Access Performance Metrics', color: 'emerald' },
          { id: UserRole.STUDENT, label: 'Student Access', icon: GraduationCap, desc: 'Submit Anonymous Feedback', color: 'blue' },
        ].map((r) => (
          <button
            key={r.id}
            onClick={() => setRole(r.id)}
            className="group flex items-center gap-6 p-6 bg-white border border-slate-200 rounded-[2.5rem] hover:border-blue-600 hover:shadow-2xl transition-all text-left"
          >
            <div className={`w-14 h-14 rounded-2xl bg-${r.color}-50 text-${r.color}-600 flex items-center justify-center shrink-0 group-hover:bg-${r.color}-600 group-hover:text-white transition-all`}>
