            </div>
            <ChevronRight className="text-slate-200 group-hover:text-blue-600 transition-all" size={20} />
          </button>
        ))}
      </div>
    </div>
  );

  const renderAuthForm = () => (
    <div className="space-y-6 animate-in slide-in-from-right duration-500 max-w-md w-full">
