          <div className="absolute top-0 right-0 w-96 h-96 bg-blue-600 rounded-full blur-[100px]"></div>
          <div className="absolute bottom-0 left-0 w-96 h-96 bg-indigo-600 rounded-full blur-[100px]"></div>
        </div>
        <div className="relative z-10 text-center">
          <LockKeyhole size={64} className="mx-auto mb-8 text-blue-400" />
          <h1 className="text-4xl font-black uppercase tracking-tighter leading-none mb-4">SRK-IT <br/> IDENTITY</h1>
