// Simple deterministic hash function for simulation (Client-side HashCode)
const generateHashCode = (data: string): string => {
  let hash = 0;
  for (let i = 0; i < data.length; i++) {
    const char = data.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return '0x' + Math.abs(hash).toString(16).padStart(16, '0') + Math.random().toString(16).slice(2, 8);
};

const FeedbackPortal: React.FC<FeedbackPortalProps> = ({ 
  onSubmit, 
  onLogout, 
  user, 
  subjects, 
  sessionRegistry,
  theoryQuestions,
  labQuestions,
  isGlobalSessionActive
}) => {
  const [type, setType] = useState<FeedbackType>(FeedbackType.THEORY);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [suggestions, setSuggestions] = useState('');
  const [hasSigned, setHasSigned] = useState(false);
  const [lastSubmission, setLastSubmission] = useState<SimulationResult & { hashCode?: string } | null>(null);
  const [matrixScores, setMatrixScores] = useState<Record<string, Record<number, number>>>({});

  const [activeSubjects, setActiveSubjects] = useState<Subject[]>([]);
  const [isSessionOpen, setIsSessionOpen] = useState(false);

  useEffect(() => {
    const sessionKey = `${user.department}-${user.semester}`;
    const isOpen = (sessionRegistry[sessionKey] || false) && isGlobalSessionActive;
    setIsSessionOpen(isOpen);

    if (isOpen) {
      const filtered = subjects.filter(s => 
        s.department === user.department && 
        s.semester === user.semester &&
        s.type === type
      );
      setActiveSubjects(filtered);
    } else {
      setActiveSubjects([]);
    }
  }, [user.department, user.semester, subjects, sessionRegistry, type, isGlobalSessionActive]);

  const handleScoreChange = (subjectId: string, metricIdx: number, val: number) => {
    setMatrixScores(prev => ({
      ...prev,
      [subjectId]: {
        ...(prev[subjectId] || {}),
        [metricIdx]: val
      }
    }));
  };

  const metrics = useMemo(() => {
    const dept = user.department || 'CSE';
    const list = type === FeedbackType.THEORY ? (theoryQuestions[dept] || []) : (labQuestions[dept] || []);
    return type === FeedbackType.THEORY ? list.slice(0, 10) : list.slice(0, 5);
  }, [type, user.department, theoryQuestions, labQuestions]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isSessionOpen) return;

    let allFilled = true;
    activeSubjects.forEach(s => {
      metrics.forEach((_, idx) => {
        if (!matrixScores[s.id]?.[idx]) allFilled = false;
      });
    });

    if (!allFilled) return alert('Please complete all ratings.');
    if (!hasSigned) return alert('Acknowledgment required.');

    setIsSubmitting(true);
    try {
      // Generate Anonymous HashCode
      const hashCode = generateHashCode(JSON.stringify(matrixScores) + suggestions + Date.now());

      const result = await sendGaslessFeedback({
        matrixScores,
        suggestions,
        department: user.department,
        semester: user.semester,
        type,
        bundleSize: activeSubjects.length,
        timestamp: Date.now(),
        hashCode // Anchored to state
      });

      // Submit each entry to global state for Analytics (Simulated)
      activeSubjects.forEach(s => {
        onSubmit({
          id: Math.random().toString(36).substr(2, 9),
          type,
          facultyId: 'F001', // Should map to actual faculty
          subjectId: s.id,
          department: user.department as Department,
          semester: user.semester as any,
          data: matrixScores[s.id],
          timestamp: Date.now(),
          encryptedHash: hashCode
        });
      });

      setLastSubmission({ ...result, hashCode });
      setIsSubmitted(true);
      setTimeout(() => onLogout(), 12000);
    } catch {
      alert("Submission failed. Network error.");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (isSubmitted) {
    return (
      <div className="bg-white p-12 rounded-[3rem] border border-slate-200 shadow-2xl text-center max-w-2xl mx-auto animate-in zoom-in duration-500">
        <div className="w-24 h-24 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-6 mx-auto animate-bounce">
          <CheckCircle2 size={48} />
        </div>
        <h2 className="text-3xl font-black text-slate-900 mb-2">Anonymous Hash Generated</h2>
        <div className="p-4 bg-slate-50 border border-slate-200 rounded-2xl font-mono text-[10px] text-blue-600 mb-8 break-all">
          {lastSubmission?.hashCode}
        </div>
        <p className="text-slate-500 mb-6 font-medium">Your identity has been purged. This HashCode is the only record of your feedback on the Polygon Amoy Testnet.</p>
        <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden"><div className="bg-blue-600 h-full animate-[progress_12s_linear_forwards]"></div></div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto space-y-6">
      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-2xl overflow-hidden">
        <div className="p-8 md:p-12 border-b-2 border-slate-100 bg-slate-50/30 flex flex-col md:flex-row justify-between items-center gap-6">
          <div className="flex items-center gap-4">
            <div className="p-4 bg-slate-900 rounded-2xl text-white">
               <Fingerprint size={24} />
            </div>
            <div>
              <h1 className="text-lg font-black">{user.department} NODE v4.0</h1>
              <p className="text-[10px] font-black uppercase text-slate-500 tracking-widest">Eligibility Verified • Identity: Hidden</p>
            </div>
          </div>
          <div className="flex bg-slate-200 p-1.5 rounded-2xl">
            <button type="button" onClick={() => setType(FeedbackType.THEORY)} className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${type === FeedbackType.THEORY ? 'bg-white shadow-md text-blue-600' : 'text-slate-500'}`}>Theory Audit</button>
            <button type="button" onClick={() => setType(FeedbackType.LAB)} className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${type === FeedbackType.LAB ? 'bg-white shadow-md text-emerald-600' : 'text-slate-500'}`}>Lab Audit</button>
          </div>
        </div>

        {(!isSessionOpen || activeSubjects.length === 0) ? (
          <div className="p-24 text-center space-y-6">
             <div className="p-10 bg-slate-50 rounded-full w-fit mx-auto text-slate-300"><SearchX size={64} /></div>
             <h3 className="text-2xl font-black">Cohort Gateway Closed</h3>
             <p className="text-slate-500 max-w-sm mx-auto">Access to this Departmental Node is currently restricted by the Academic Council.</p>
          </div>
        ) : (
          <form onSubmit={handleSubmit}>
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="bg-slate-50 border-y border-slate-100">
                    <th className="p-8 text-left text-[11px] font-black text-slate-400 uppercase tracking-widest min-w-[350px]">Assessment Attribute</th>
                    {activeSubjects.map(s => <th key={s.id} className="p-8 text-center"><span className="block text-sm font-black">{s.id}</span></th>)}
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {metrics.map((metric, mIdx) => (
                    <tr key={mIdx} className="hover:bg-slate-50/50">
                      <td className="p-8 text-sm font-bold text-slate-700">{metric}</td>
                      {activeSubjects.map(s => (
                        <td key={s.id} className="p-6 text-center">
                          <select 
                            value={matrixScores[s.id]?.[mIdx] || ''} 
                            onChange={(e) => handleScoreChange(s.id, mIdx, parseInt(e.target.value))}
                            className={`w-14 h-14 rounded-2xl border-2 text-center font-black transition-all ${matrixScores[s.id]?.[mIdx] ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-400'}`}
                          >
                            <option value="">-</option>
                            {[5, 4, 3, 2, 1].map(n => <option key={n} value={n}>{n}</option>)}
                          </select>
                        </td>
                      ))}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            <div className="p-10 bg-white border-t border-slate-100 space-y-10">
              <textarea 
                value={suggestions} 
                onChange={(e) => setSuggestions(e.target.value)} 
                placeholder="Enter encrypted suggestions for faculty improvement..." 
                className="w-full p-8 bg-slate-50 border-2 border-slate-100 rounded-[2rem] min-h-[150px] font-bold outline-none focus:border-blue-600 transition-all"
              />
              <div className="flex flex-col md:flex-row gap-6">
                <button type="button" onClick={() => setHasSigned(!hasSigned)} className={`flex-1 p-8 rounded-[2rem] border-2 transition-all flex items-center gap-4 ${hasSigned ? 'bg-blue-600 border-blue-600 text-white shadow-xl' : 'bg-slate-50 border-slate-100 text-slate-400'}`}>
                  <ShieldCheck /> <span className="text-[10px] font-black uppercase text-left">Confirm Identity Erasure & Feedback Integrity Protocol</span>
                </button>
                <button type="submit" disabled={isSubmitting} className="flex-1 py-8 bg-slate-900 text-white rounded-[2rem] font-black uppercase tracking-widest text-xs flex items-center justify-center gap-4 transition-all active:scale-95 disabled:opacity-50">
                  {isSubmitting ? <><Loader2 className="animate-spin" /> Anchoring Hash...</> : <><Send size={20} /> Submit Feedback</>}
                </button>
              </div>
            </div>
          </form>
        )}
      </div>
    </div>
  );
};

