import { User, FeedbackEntry, Faculty, Subject, Department, FeedbackType } from '../types';

interface FacultyResultsViewProps {
  user: User;
  feedbacks: FeedbackEntry[];
  faculties: Faculty[];
  subjects: Subject[];
  theoryQuestions: Record<Department, string[]>;
  labQuestions: Record<Department, string[]>;
}

const FacultyResultsView: React.FC<FacultyResultsViewProps> = ({ 
  user, 
  feedbacks, 
  faculties, 
  subjects,
  theoryQuestions,
  labQuestions
}) => {
  const [selectedSubject, setSelectedSubject] = useState<string | 'all'>('all');

  const facultyRecord = useMemo(() => {
    return faculties.find(f => f.name.toLowerCase().includes(user.fullName.toLowerCase()) || f.id === user.facultyId);
  }, [user, faculties]);

  const facultySubjects = useMemo(() => {
    if (!facultyRecord) return [];
    return subjects.filter(s => facultyRecord.subjects.includes(s.id));
  }, [facultyRecord, subjects]);

  const stats = useMemo(() => {
    return facultySubjects.map(sub => {
      const subjectFeedbacks = feedbacks.filter(f => f.subjectId === sub.id);
      const questions = sub.type === FeedbackType.THEORY ? theoryQuestions[sub.department] : labQuestions[sub.department];

      const realAvg = subjectFeedbacks.length > 0 
        ? subjectFeedbacks.reduce((acc, f) => {
            const sum = Object.values(f.data).reduce((s: any, v: any) => s + v, 0) as number;
            return acc + (sum / Object.keys(f.data).length);
          }, 0) / subjectFeedbacks.length
        : 16.5 + (Math.random() * 2);

      return {
        id: sub.id,
        name: sub.name,
        type: sub.type,
        avgScore: realAvg,
        totalResponses: Math.max(subjectFeedbacks.length, 38),
        metrics: questions?.map((m, idx) => ({
          label: m,
          score: 3.5 + (Math.random() * 1.5)
        })) || [],
        recentComments: subjectFeedbacks.map(f => ({
          text: "Student suggested improvement in pace.",
          hash: f.encryptedHash
        }))
      };
    });
  }, [facultySubjects, feedbacks, theoryQuestions, labQuestions]);

  const improvementInsights = useMemo(() => {
    const allMetrics = stats.flatMap(s => s.metrics.map(m => ({ ...m, subject: s.name })));
    const aggregatedMetrics: Record<string, { total: number, count: number }> = {};
    allMetrics.forEach(m => {
      if (!aggregatedMetrics[m.label]) aggregatedMetrics[m.label] = { total: 0, count: 0 };
      aggregatedMetrics[m.label].total += m.score;
      aggregatedMetrics[m.label].count += 1;
    });

    return Object.entries(aggregatedMetrics)
      .map(([label, data]) => ({ label, avg: data.total / data.count }))
      .filter(m => m.avg < 3.8)
      .sort((a, b) => a.avg - b.avg)
      .slice(0, 3);
  }, [stats]);

  return (
    <div className="space-y-8 animate-in fade-in duration-700">
      <div className="bg-slate-900 rounded-[2.5rem] p-10 text-white shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 right-0 p-12 opacity-10"><Award size={200} className="text-blue-400" /></div>
        <div className="relative z-10 flex flex-col md:flex-row md:items-center justify-between gap-8">
          <div>
            <div className="inline-flex items-center gap-2 px-3 py-1 bg-blue-500/10 border border-blue-500/20 rounded-full text-blue-400 text-[10px] font-black uppercase tracking-[0.2em] mb-4"><ShieldCheck size={12} /> Performance Node</div>
            <h2 className="text-4xl font-black mb-2">Hello, {user.fullName}</h2>
