const AnalysisView: React.FC<AnalysisViewProps> = ({ feedbacks, user }) => {
  const [selectedDept, setSelectedDept] = useState<Department>(user.department || 'CSE');
  const [selectedSem, setSelectedSem] = useState<Semester>(user.semester || '3.1');
  const [analysisMode, setAnalysisMode] = useState<'current' | 'historical'>('current');

  // Simulated Historical Data (3 Years)
  const historicalTrends = useMemo(() => [
    { year: '2022', score: 17.4 },
    { year: '2023', score: 18.1 },
    { year: '2024', score: 18.6 }
  ], []);

  const reportData = FACULTY_DATA.filter(f => f.department === selectedDept)
    .map((fac, index) => {
      const sub = SUBJECTS.find(s => fac.subjects.includes(s.id) && s.semester === selectedSem);
      if (!sub) return null;

      const realPoints = feedbacks.filter(f => f.subjectId === sub.id).reduce((acc, f) => {
         const sum = Object.values(f.data).reduce((s: any, v: any) => s + v, 0) as number;
         return acc + (sum / Object.keys(f.data).length);
      }, 0);

      return {
        sNo: index + 1,
        faculty: fac.name,
        subject: sub.name,
        points: realPoints > 0 ? realPoints : 17.5 + (Math.random() * 2),
        dept: selectedDept,
        sem: selectedSem
      };
    }).filter(Boolean);

  const currentHodName = HOD_LIST[selectedDept] || "HOD";

