        <button onClick={() => setAnalysisMode('historical')} className={`flex items-center gap-2 px-8 py-3 rounded-2xl text-[10px] font-black uppercase transition-all ${analysisMode === 'historical' ? 'bg-white shadow-md text-indigo-600' : 'text-slate-500'}`}><History size={14}/> Historical Trends</button>
      </div>

      {analysisMode === 'historical' ? (
        <div className="bg-white p-12 rounded-[3rem] border border-slate-200 shadow-2xl space-y-10 animate-in zoom-in">
           <div className="flex items-center justify-between">
              <h3 className="text-2xl font-black text-slate-900 flex items-center gap-3"><TrendingUp className="text-indigo-600" /> 3-Year Performance Trend</h3>
