}

import React, { useState } from 'react';
import { Search, Edit3, Save, X, UserPlus, Filter, Trash2, IdCard } from 'lucide-react';
import { Faculty } from '../types';

interface FacultyControlProps {
  faculties: Faculty[];
  onUpdateFaculty: (updated: Faculty) => void;
}

const FacultyControl: React.FC<FacultyControlProps> = ({ faculties, onUpdateFaculty }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Faculty | null>(null);

  const filtered = faculties.filter(f => 
    f.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    f.id.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const startEdit = (faculty: Faculty) => {
    setEditingId(faculty.id);
    setEditForm({ ...faculty });
  };

  const handleSave = () => {
    if (editForm) {
      onUpdateFaculty(editForm);
      setEditingId(null);
      setEditForm(null);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex flex-col md:flex-row justify-between items-center gap-4">
        <div className="relative w-full md:w-96">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
          <input 
            type="text" 
            placeholder="Search Faculty ID or Name..." 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-12 pr-4 py-3 bg-white border border-slate-200 rounded-2xl text-sm font-semibold outline-none focus:ring-2 focus:ring-blue-500"
          />
        </div>
        <button className="flex items-center gap-2 px-6 py-3 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg">
          <UserPlus size={16} /> Add New Node
        </button>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="p-6 text-[10px] font-black uppercase text-slate-400 tracking-widest">ID</th>
              <th className="p-6 text-[10px] font-black uppercase text-slate-400 tracking-widest">Faculty Name</th>
              <th className="p-6 text-[10px] font-black uppercase text-slate-400 tracking-widest">Designation</th>
              <th className="p-6 text-[10px] font-black uppercase text-slate-400 tracking-widest">Department</th>
              <th className="p-6 text-[10px] font-black uppercase text-slate-400 tracking-widest text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filtered.map((f) => (
              <tr key={f.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="p-6 font-mono font-bold text-blue-600">{f.id}</td>
                <td className="p-6">
                  {editingId === f.id ? (
                    <input 
                      type="text" 
                      value={editForm?.name} 
                      onChange={(e) => setEditForm(prev => prev ? { ...prev, name: e.target.value } : null)}
                      className="px-3 py-1 bg-white border border-blue-500 rounded-lg outline-none font-bold"
                    />
                  ) : (
                    <span className="font-bold text-slate-700">{f.name}</span>
                  )}
                </td>
                <td className="p-6">
                  {editingId === f.id ? (
                    <input 
                      type="text" 
                      value={editForm?.designation || ''} 
                      onChange={(e) => setEditForm(prev => prev ? { ...prev, designation: e.target.value } : null)}
                      className="px-3 py-1 bg-white border border-blue-500 rounded-lg outline-none font-bold"
                      placeholder="e.g. Professor"
                    />
                  ) : (
                    <span className="text-slate-500 font-semibold">{f.designation || 'Asst. Professor'}</span>
                  )}
                </td>
                <td className="p-6">
                  <span className="px-3 py-1 bg-slate-100 rounded-lg text-[10px] font-black uppercase text-slate-600">{f.department}</span>
                </td>
                <td className="p-6 text-right">
                  {editingId === f.id ? (
                    <div className="flex justify-end gap-2">
                      <button onClick={handleSave} className="p-2 bg-emerald-100 text-emerald-600 rounded-lg"><Save size={18} /></button>
                      <button onClick={() => setEditingId(null)} className="p-2 bg-red-100 text-red-600 rounded-lg"><X size={18} /></button>
                    </div>
                  ) : (
                    <div className="flex justify-end gap-2">
                      <button onClick={() => startEdit(f)} className="p-2 text-slate-400 hover:text-blue-600 transition-colors"><Edit3 size={18} /></button>
                      <button className="p-2 text-slate-400 hover:text-red-600 transition-colors"><Trash2 size={18} /></button>
                    </div>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default FacultyControl;

import React, { useState } from 'react';
import { Database, Zap, FileText, Settings, Save, RefreshCw, AlertTriangle, CheckCircle2 } from 'lucide-react';
import { Department } from '../types';

interface DatasetManagerProps {
  theoryQuestions: Record<Department, string[]>;
  labQuestions: Record<Department, string[]>;
  onUpdateQuestions: (type: 'THEORY' | 'LAB', questions: string[]) => void;
  onBulkSync: (rawData: string) => void;
}

const DatasetManager: React.FC<DatasetManagerProps> = ({ 
  theoryQuestions, 
  labQuestions, 
  onUpdateQuestions,
  onBulkSync
}) => {
  const [rawData, setRawData] = useState('');
  const [activeDept, setActiveDept] = useState<Department>('CSE');
  const [tempTheory, setTempTheory] = useState(theoryQuestions['CSE']);
  const [tempLab, setTempLab] = useState(labQuestions['CSE']);
  const [isSyncing, setIsSyncing] = useState(false);

  const handleUpdateTheory = (idx: number, val: string) => {
    const updated = [...tempTheory];
    updated[idx] = val;
    setTempTheory(updated);
  };

  const handleUpdateLab = (idx: number, val: string) => {
    const updated = [...tempLab];
    updated[idx] = val;
    setTempLab(updated);
  };

  const handleSyncClick = () => {
    setIsSyncing(true);
    onBulkSync(rawData);
    setTimeout(() => setIsSyncing(false), 2000);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Bulk Update Section */}
      <div className="bg-white p-10 rounded-[3rem] border border-slate-200 shadow-sm space-y-6">
        <div className="flex items-center gap-4">
          <div className="p-3 bg-blue-100 text-blue-600 rounded-2xl">
            <Database size={24} />
          </div>
          <div>
            <h3 className="text-xl font-black text-slate-900 uppercase tracking-tight">Bulk Registry Protocol</h3>
            <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mt-1">Anchor Raw Data to Blockchain Node</p>
          </div>
        </div>

        <textarea 
          value={rawData}
          onChange={(e) => setRawData(e.target.value)}
          placeholder="Paste raw dataset text here (e.g. F001, Dr. Rao, CSE, Professor)..."
          className="w-full h-48 p-6 bg-slate-50 border-2 border-slate-100 rounded-[2rem] font-mono text-xs outline-none focus:border-blue-500 transition-all"
        />

        <div className="flex justify-between items-center">
          <div className="flex items-center gap-2 text-amber-600 font-bold text-[10px] uppercase tracking-widest">
            <AlertTriangle size={14} /> Warning: This will overwrite existing registry state
          </div>
          <button 
            onClick={handleSyncClick}
            disabled={isSyncing || !rawData.trim()}
            className="flex items-center gap-3 px-10 py-5 bg-slate-900 text-white rounded-[1.5rem] font-black uppercase text-xs tracking-widest shadow-xl disabled:opacity-50 active:scale-95 transition-all"
          >
            {isSyncing ? <RefreshCw className="animate-spin" size={18} /> : <Zap size={18} />} Run Global Sync
          </button>
        </div>
      </div>

      {/* Attribute Control Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-10 rounded-[3rem] border border-slate-200 shadow-sm space-y-6">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-lg font-black text-slate-900 flex items-center gap-2 uppercase tracking-tight">
              <FileText className="text-blue-600" /> Theory Attributes
            </h3>
            <button 
              onClick={() => onUpdateQuestions('THEORY', tempTheory)}
              className="px-4 py-2 bg-blue-50 text-blue-600 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-blue-600 hover:text-white transition-all"
            >
              Update Protocol
            </button>
          </div>
          <div className="space-y-3">
            {tempTheory.map((q, i) => (
              <div key={i} className="flex items-center gap-3">
                <span className="w-8 h-8 rounded-lg bg-slate-100 flex items-center justify-center font-black text-[10px] text-slate-400">{i + 1}</span>
                <input 
                  type="text" 
                  value={q} 
                  onChange={(e) => handleUpdateTheory(i, e.target.value)}
                  className="flex-1 px-4 py-2.5 bg-slate-50 border border-slate-100 rounded-xl text-xs font-bold text-slate-700 outline-none focus:bg-white focus:border-blue-500 transition-all"
                />
              </div>
            ))}
          </div>
        </div>

        <div className="bg-white p-10 rounded-[3rem] border border-slate-200 shadow-sm space-y-6">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-lg font-black text-slate-900 flex items-center gap-2 uppercase tracking-tight">
              <Settings className="text-emerald-600" /> Lab Attributes
            </h3>
            <button 
              onClick={() => onUpdateQuestions('LAB', tempLab)}
              className="px-4 py-2 bg-emerald-50 text-emerald-600 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-emerald-600 hover:text-white transition-all"
            >
              Update Protocol
            </button>
          </div>
          <div className="space-y-3">
            {tempLab.map((q, i) => (
              <div key={i} className="flex items-center gap-3">
                <span className="w-8 h-8 rounded-lg bg-slate-100 flex items-center justify-center font-black text-[10px] text-slate-400">{i + 1}</span>
                <input 
                  type="text" 
                  value={q} 
                  onChange={(e) => handleUpdateLab(i, e.target.value)}
                  className="flex-1 px-4 py-2.5 bg-slate-50 border border-slate-100 rounded-xl text-xs font-bold text-slate-700 outline-none focus:bg-white focus:border-emerald-500 transition-all"
                />
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
