    setTimeout(() => setToast(null), 3000);
  };

  const handleUpdateQuestions = (type: 'THEORY' | 'LAB', questions: string[]) => {
    if (type === 'THEORY') {
      setTheoryQuestions(prev => {
        const next = { ...prev };
        Object.keys(next).forEach(dept => { next[dept as Department] = [...questions]; });
        return next;
      });
    } else {
      setLabQuestions(prev => {
        const next = { ...prev };
        Object.keys(next).forEach(dept => { next[dept as Department] = [...questions]; });
        return next;
