                          <td className="p-10 text-emerald-600 font-mono text-[11px] max-w-xs truncate" title={f.encryptedHash}>{f.encryptedHash}</td>
                       </tr>
                     ))}
                     {feedbacks.length === 0 && (
                       <tr><td colSpan={4} className="p-20 text-center text-slate-300 font-black uppercase tracking-widest">No entries recorded in current session</td></tr>
                     )}
                  </tbody>
               </table>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

