import React, { useState, useEffect, useMemo } from 'react';
import { 
  Send, 
  CheckCircle2, 
  Lock,
  Loader2,
  Fingerprint,
  SearchX,
  ShieldCheck
} from 'lucide-react';
import { FeedbackType, FeedbackEntry, User, Subject, Department } from '../types';
import { sendGaslessFeedback } from '../services/web3Service';

interface FeedbackPortalProps {
  onSubmit: (entry: FeedbackEntry) => void;
  onLogout: () => void;
  user: User;
  subjects: Subject[];
  sessionRegistry: Record<string, boolean>;
  theoryQuestions: Record<Department, string[]>;
  labQuestions: Record<Department, string[]>;
  isGlobalSessionActive: boolean;
}

const FeedbackPortal: React.FC<FeedbackPortalProps> = ({ 
  onSubmit, 
  onLogout, 
  user, 
  subjects, 
  sessionRegistry,
  theoryQuestions,
  labQuestions,
  isGlobalSessionActive
}) => {
  const [type, setType] = useState<FeedbackType>(FeedbackType.THEORY);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [suggestions, setSuggestions] = useState('');
  const [matrixScores, setMatrixScores] = useState<Record<string, Record<number, number>>>({});
  const [activeSubjects, setActiveSubjects] = useState<Subject[]>([]);
  const [isSessionOpen, setIsSessionOpen] = useState(false);

  useEffect(() => {
    const sessionKey = `${user.department}-${user.semester}`;
    const isOpen = (sessionRegistry[sessionKey] || false) && isGlobalSessionActive;
    setIsSessionOpen(isOpen);

    if (isOpen) {
      const filtered = subjects.filter(s => 
        s.department === user.department && 
        s.semester === user.semester &&
        s.type === type
      );
      setActiveSubjects(filtered);
    }
  }, [user.department, user.semester, subjects, sessionRegistry, type, isGlobalSessionActive]);

  const metrics = useMemo(() => {
    const dept = user.department || 'CSE';
    const list = type === FeedbackType.THEORY ? (theoryQuestions[dept] || []) : (labQuestions[dept] || []);
    return type === FeedbackType.THEORY ? list.slice(0, 10) : list.slice(0, 10);
  }, [type, user.department, theoryQuestions, labQuestions]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isSessionOpen || activeSubjects.length === 0) return;

    setIsSubmitting(true);
    try {
      // Logic for bundle submission...
      activeSubjects.forEach(s => {
        onSubmit({
          id: Math.random().toString(36).substr(2, 9),
          type,
          facultyId: 'F001',
          subjectId: s.id,
          department: user.department as Department,
          semester: user.semester as any,
          data: matrixScores[s.id] || {},
          timestamp: Date.now(),
          encryptedHash: "HIDDEN_BY_PROTOCOL" 
        });
      });

      setIsSubmitted(true);
      setTimeout(() => onLogout(), 3000);
    } catch {
      alert("Submission error.");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (isSubmitted) {
    return (
      <div className="bg-white p-20 rounded-[4rem] border border-slate-200 shadow-2xl text-center max-w-xl mx-auto animate-in zoom-in duration-500">
        <div className="w-24 h-24 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center mb-8 mx-auto animate-bounce">
          <CheckCircle2 size={48} />
        </div>
        <h2 className="text-3xl font-black text-slate-900 mb-4 uppercase tracking-tight">Feedback Submitted</h2>
        <p className="text-slate-500 font-bold uppercase text-[10px] tracking-[0.2em]">Redirecting to Core Terminal...</p>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto space-y-8 animate-in fade-in duration-500">
      <div className="bg-white rounded-[3rem] border border-slate-200 shadow-2xl overflow-hidden">
        <div className="p-10 border-b border-slate-100 bg-slate-50/50 flex flex-col md:flex-row justify-between items-center gap-6">
          <div className="flex items-center gap-4">
            <div className="p-4 bg-slate-900 rounded-2xl text-white shadow-xl">
               <Fingerprint size={24} />
            </div>
            <div>
              <h1 className="text-xl font-black uppercase tracking-tight">Academic Audit Node</h1>
              <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Semester: {user.semester} • Identity: Hidden</p>
            </div>
          </div>
          <div className="flex bg-slate-200 p-1.5 rounded-2xl shadow-inner">
            <button type="button" onClick={() => setType(FeedbackType.THEORY)} className={`px-8 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${type === FeedbackType.THEORY ? 'bg-white shadow-md text-blue-600' : 'text-slate-500'}`}>Theory</button>
            <button type="button" onClick={() => setType(FeedbackType.LAB)} className={`px-8 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${type === FeedbackType.LAB ? 'bg-white shadow-md text-emerald-600' : 'text-slate-500'}`}>Lab</button>
          </div>
        </div>

        {(!isSessionOpen || activeSubjects.length === 0) ? (
          <div className="p-32 text-center space-y-6">
             <SearchX size={64} className="mx-auto text-slate-200" />
             <h3 className="text-2xl font-black uppercase text-slate-400">Node Closed</h3>
          </div>
        ) : (
          <form onSubmit={handleSubmit} className="divide-y divide-slate-100">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50/50">
                  <tr>
                    <th className="p-8 text-[11px] font-black text-slate-400 uppercase tracking-widest min-w-[400px]">Attribute</th>
                    {activeSubjects.map(s => <th key={s.id} className="p-8 text-center text-xs font-black text-slate-900 border-l border-slate-100">{s.id}</th>)}
                  </tr>
                </thead>
                <tbody>
                  {metrics.map((metric, mIdx) => (
                    <tr key={mIdx} className="hover:bg-slate-50/30 transition-colors">
                      <td className="p-8 text-sm font-bold text-slate-700">{metric}</td>
                      {activeSubjects.map(s => (
                        <td key={s.id} className="p-8 text-center border-l border-slate-100">
                          <select 
                            value={matrixScores[s.id]?.[mIdx] || ''} 
                            onChange={(e) => setMatrixScores({...matrixScores, [s.id]: {...(matrixScores[s.id]||{}), [mIdx]: parseInt(e.target.value)}})}
                            className={`w-12 h-12 rounded-xl border-2 text-center font-black transition-all appearance-none cursor-pointer ${matrixScores[s.id]?.[mIdx] ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-slate-50 border-slate-200 text-slate-400'}`}
                          >
                            <option value="">-</option>
                            {[5, 4, 3, 2, 1].map(n => <option key={n} value={n}>{n}</option>)}
                          </select>
                        </td>
                      ))}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            <div className="p-10 bg-white space-y-8">
              <textarea 
                value={suggestions} 
                onChange={(e) => setSuggestions(e.target.value)} 
                placeholder="Improvement suggestions (Optional)..." 
                className="w-full p-8 bg-slate-50 border-2 border-slate-100 rounded-[2.5rem] min-h-[120px] font-bold text-sm outline-none focus:border-blue-600 transition-all"
              />
              <button type="submit" disabled={isSubmitting} className="w-full py-8 bg-slate-900 text-white rounded-[2.5rem] font-black uppercase tracking-widest text-xs flex items-center justify-center gap-4 transition-all active:scale-95 disabled:opacity-50 shadow-2xl">
                {isSubmitting ? <><Loader2 className="animate-spin" /> Submitting...</> : <><Send size={20} /> Submit Feedback</>}
              </button>
            </div>
          </form>
        )}
      </div>
    </div>
  );
};

export default FeedbackPortal;

