import React, { useState } from 'react';
import { Plus, Trash2, Save, FileText, FlaskConical, AlertCircle } from 'lucide-react';
import { Department } from '../types';

interface AttributeEditorProps {
  theoryQuestions: Record<Department, string[]>;
  labQuestions: Record<Department, string[]>;
  setTheoryQuestions: (qs: Record<Department, string[]>) => void;
  setLabQuestions: (qs: Record<Department, string[]>) => void;
}

const AttributeEditor: React.FC<AttributeEditorProps> = ({ theoryQuestions, labQuestions, setTheoryQuestions, setLabQuestions }) => {
  const [activeTab, setActiveTab] = useState<'THEORY' | 'LAB'>('THEORY');
  const [currentQuestions, setCurrentQuestions] = useState<string[]>(theoryQuestions['CSE']);

  const handleAdd = () => setCurrentQuestions([...currentQuestions, "New Assessment Attribute"]);
  const handleRemove = (idx: number) => setCurrentQuestions(currentQuestions.filter((_, i) => i !== idx));
  const handleChange = (idx: number, val: string) => {
    const next = [...currentQuestions];
    next[idx] = val;
    setCurrentQuestions(next);
  };

  const handleSave = () => {
    const updated: any = {};
    Object.keys(theoryQuestions).forEach(dept => {
      updated[dept] = [...currentQuestions];
    });
    if (activeTab === 'THEORY') setTheoryQuestions(updated);
    else setLabQuestions(updated);
    alert("Global Protocol Synchronized.");
  };

  return (
    <div className="bg-white p-12 rounded-[4rem] border border-slate-200 shadow-sm space-y-10 animate-in fade-in">
      <div className="flex items-center justify-between">
        <div className="flex bg-slate-100 p-1.5 rounded-2xl">
          <button onClick={() => { setActiveTab('THEORY'); setCurrentQuestions(theoryQuestions['CSE']); }} className={`px-8 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'THEORY' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400'}`}>Theory Audit</button>
          <button onClick={() => { setActiveTab('LAB'); setCurrentQuestions(labQuestions['CSE']); }} className={`px-8 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'LAB' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-400'}`}>Lab Audit</button>
        </div>
        <button onClick={handleSave} className="flex items-center gap-2 px-8 py-3 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase shadow-xl"><Save size={16}/> Save Changes</button>
      </div>

      <div className="space-y-4">
        {currentQuestions.map((q, i) => (
          <div key={i} className="flex items-center gap-4 group">
            <span className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center font-black text-xs text-slate-300">{i + 1}</span>
            <input 
              value={q} 
              onChange={(e) => handleChange(i, e.target.value)}
              className="flex-1 px-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm outline-none focus:bg-white focus:border-blue-500 transition-all"
            />
            <button onClick={() => handleRemove(i)} className="p-3 text-slate-300 hover:text-red-500 transition-colors"><Trash2 size={18}/></button>
          </div>
        ))}
      </div>

      <button onClick={handleAdd} className="w-full py-6 border-2 border-dashed border-slate-200 rounded-[2rem] text-slate-400 hover:border-blue-500 hover:text-blue-500 transition-all flex items-center justify-center gap-2 font-black uppercase text-[10px]">
        <Plus size={18}/> Append Assessment Metric
      </button>

      <div className="p-6 bg-blue-50 border border-blue-100 rounded-3xl flex gap-4 text-blue-700">
         <AlertCircle size={20} className="shrink-0" />
         <p className="text-[11px] font-bold leading-relaxed">PROTOCOL: These attributes are globally mirrored across all Departmental Nodes. Changes will reflect instantly on the student feedback terminal.</p>
      </div>
    </div>
  );
};

