  );

  const [sessionRegistry, setSessionRegistry] = useState<Record<string, boolean>>(
    DEPARTMENTS.reduce((acc, dept) => {
      SEMESTERS.forEach(sem => { acc[`${dept}-${sem}`] = true; });
      return acc;
    }, {} as Record<string, boolean>)
  );

  const archiveSession = () => {
    // Hybrid logic: Move current state to PostgreSQL/Archive and reset blockchain node
    const newArchives: ArchiveRecord[] = faculties.map(f => ({
      sessionId: `2025_SEM1_${Date.now()}`,
      year: '2025',
      facultyId: f.id,
      dept: f.department,
      avgRating: 17.5 + (Math.random() * 2),
      semester: '3.1'
    }));
    setArchives([...archives, ...newArchives]);
    setFeedbacks([]); // Reset active feedbacks for new session
    alert("Session Archived. Current data moved to Persistence Layer.");
  };

  const handleAuth = (authenticatedUser: User) => {
    setUser(authenticatedUser);
    if (authenticatedUser.role === UserRole.ADMIN) setActiveTab('admin');
    else if (authenticatedUser.role === UserRole.FACULTY) setActiveTab('faculty_results');
    else setActiveTab('feedback');
  };

  if (!user) return <Auth onAuthenticate={handleAuth} />;

  const tabs = [
    { id: 'feedback', label: 'Vote Feedback', icon: FileText, roles: [UserRole.STUDENT] },
    { id: 'faculty_results', label: 'Performance', icon: UserCheck, roles: [UserRole.FACULTY] },
    { id: 'analysis', label: 'Analytics', icon: BarChart3, roles: [UserRole.FACULTY, UserRole.ADMIN] },
    { id: 'admin', label: 'Super-Admin', icon: Lock, roles: [UserRole.ADMIN] },
  ].filter(tab => !tab.roles || tab.roles.includes(user.role));

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-inter">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} tabs={tabs} isOpen={isSidebarOpen} toggleSidebar={() => setSidebarOpen(!isSidebarOpen)} user={user} onLogout={() => setUser(null)} />
      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <Header activeTab={tabs.find(t => t.id === activeTab)?.label || 'SRK-IT'} user={user} />
        <main className="flex-1 overflow-y-auto p-4 md:p-8">
          <div className="max-w-7xl mx-auto space-y-6">
            {activeTab === 'feedback' && <FeedbackPortal onSubmit={(e) => setFeedbacks([...feedbacks, e])} onLogout={() => setUser(null)} user={user} subjects={subjects} sessionRegistry={sessionRegistry} theoryQuestions={theoryQuestions} labQuestions={labQuestions} isGlobalSessionActive={isGlobalSessionActive} />}
            {activeTab === 'faculty_results' && <FacultyResultsView user={user} feedbacks={feedbacks} faculties={faculties} subjects={subjects} />}
            {activeTab === 'analysis' && <AnalysisView feedbacks={feedbacks} user={user} />}
            {activeTab === 'admin' && (
              <ProtectedAdminRoute user={user}>
                <AdminDashboard 
                  subjects={subjects} setSubjects={setSubjects}
                  faculties={faculties} setFaculties={setFaculties}
                  sessionRegistry={sessionRegistry} setSessionRegistry={setSessionRegistry}
                  theoryQuestions={theoryQuestions} setTheoryQuestions={setTheoryQuestions}
                  labQuestions={labQuestions} setLabQuestions={setLabQuestions}
                  isGlobalSessionActive={isGlobalSessionActive} setIsGlobalSessionActive={setIsGlobalSessionActive}
                  user={user} feedbacks={feedbacks} archives={archives} onArchiveSession={archiveSession}
                />
              </ProtectedAdminRoute>
            )}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

