                      <CheckCircle2 size={18} className="text-emerald-500 group-hover:scale-110 transition-transform" />
                    ) : (
                      <Power size={18} className="text-slate-300 group-hover:text-red-400 transition-colors" />
                    )}
                  </button>
                );
              })}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

