import React, { useState, useEffect, useMemo } from 'react';
import { 
  Send, 
  CheckCircle2, 
  Lock,
  Loader2,
  Fingerprint,
  SearchX,
  ShieldCheck,
  UserCheck
} from 'lucide-react';
import { FeedbackType, FeedbackEntry, User, Subject, Department, Faculty } from '../types';

interface FeedbackPortalProps {
  onSubmit: (entry: FeedbackEntry) => void;
  onLogout: () => void;
  user: User;
  subjects: Subject[];
  faculties: Faculty[];
  sessionRegistry: Record<string, boolean>;
  theoryQuestions: Record<Department, string[]>;
  labQuestions: Record<Department, string[]>;
  isGlobalSessionActive: boolean;
}

const FeedbackPortal: React.FC<FeedbackPortalProps> = ({ 
  onSubmit, 
  onLogout, 
  user, 
  subjects, 
  faculties,
  sessionRegistry, 
  theoryQuestions,
  labQuestions,
  isGlobalSessionActive
}) => {
  const [type, setType] = useState<FeedbackType>(FeedbackType.THEORY);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [suggestions, setSuggestions] = useState('');
  const [matrixScores, setMatrixScores] = useState<Record<string, Record<number, number>>>({});
  const [isSessionOpen, setIsSessionOpen] = useState(false);

  // MAPPING LOGIC: Filter subjects for student's Dept-Sem
  const activeSubjects = useMemo(() => {
    return subjects.filter(s => 
      s.department === user.department && 
      s.semester === user.semester &&
      s.type === type
    );
  }, [subjects, user.department, user.semester, type]);

  // Find faculty assigned to these subjects based on Faculty-Course Mapping
  const mappedFacultyForSubject = (subjectId: string) => {
    return faculties.find(f => f.subjects.includes(subjectId))?.name || 'Assigned Faculty';
  };

  const mappedFacultyIdForSubject = (subjectId: string) => {
    return faculties.find(f => f.subjects.includes(subjectId))?.id || 'F000';
  };

  useEffect(() => {
    const sessionKey = `${user.department}-${user.semester}`;
    const isOpen = (sessionRegistry[sessionKey] || false) && isGlobalSessionActive;
    setIsSessionOpen(isOpen);
  }, [user.department, user.semester, sessionRegistry, isGlobalSessionActive]);

  const metrics = useMemo(() => {
    const dept = user.department || 'CSE';
    const list = type === FeedbackType.THEORY ? (theoryQuestions[dept] || []) : (labQuestions[dept] || []);
    return list.slice(0, 10);
  }, [type, user.department, theoryQuestions, labQuestions]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isSessionOpen || activeSubjects.length === 0) return;

    // Validate all scores selected
    const allScored = activeSubjects.every(s => 
      metrics.every((_, idx) => matrixScores[s.id]?.[idx])
    );

    if (!allScored) {
      alert("Protocol Error: All assessment attributes must be scored for session finalization.");
      return;
    }

    setIsSubmitting(true);
    try {
      // Logic for bundle submission to the blockchain node
      activeSubjects.forEach(s => {
        onSubmit({
          id: Math.random().toString(36).substr(2, 9),
          type,
          facultyId: mappedFacultyIdForSubject(s.id),
          subjectId: s.id,
          department: user.department as Department,
          semester: user.semester as any,
          data: matrixScores[s.id] || {},
          timestamp: Date.now(),
          encryptedHash: "HIDDEN_BY_PROTOCOL" 
        });
      });

      setIsSubmitted(true);
      setTimeout(() => onLogout(), 3000);
    } catch {
      alert("Ledger Connection Error: Failed to anchor feedback scores.");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (isSubmitted) {
    return (
      <div className="bg-white p-20 rounded-[4rem] border border-slate-200 shadow-2xl text-center max-w-xl mx-auto animate-in zoom-in duration-500">
        <div className="w-24 h-24 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center mb-8 mx-auto animate-bounce">
          <CheckCircle2 size={48} />
        </div>
        <h2 className="text-3xl font-black text-slate-900 mb-4 uppercase tracking-tight">Feedback Submitted</h2>
        <p className="text-slate-500 font-bold uppercase text-[10px] tracking-[0.2em]">Data Anchored to Ledger • Redirecting...</p>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto space-y-8 animate-in fade-in duration-500">
      <div className="bg-white rounded-[3rem] border border-slate-200 shadow-2xl overflow-hidden">
        <div className="p-10 border-b border-slate-100 bg-slate-50/50 flex flex-col md:flex-row justify-between items-center gap-6">
          <div className="flex items-center gap-4">
            <div className="p-4 bg-slate-900 rounded-2xl text-white shadow-xl">
               <Fingerprint size={24} />
            </div>
            <div>
              <h1 className="text-xl font-black uppercase tracking-tight">Academic Audit Node</h1>
              <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest">
                Branch: {user.department} • Sem: {user.semester} • Identity: Purged
              </p>
            </div>
          </div>
          <div className="flex bg-slate-200 p-1.5 rounded-2xl shadow-inner">
            <button type="button" onClick={() => setType(FeedbackType.THEORY)} className={`px-8 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${type === FeedbackType.THEORY ? 'bg-white shadow-md text-blue-600' : 'text-slate-500'}`}>Theory Audit</button>
            <button type="button" onClick={() => setType(FeedbackType.LAB)} className={`px-8 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${type === FeedbackType.LAB ? 'bg-white shadow-md text-emerald-600' : 'text-slate-500'}`}>Lab Audit</button>
          </div>
        </div>

        {(!isSessionOpen || activeSubjects.length === 0) ? (
          <div className="p-32 text-center space-y-6">
             <div className="w-24 h-24 bg-slate-100 rounded-full flex items-center justify-center mx-auto text-slate-300">
                <SearchX size={48} />
             </div>
             <div>
               <h3 className="text-2xl font-black uppercase text-slate-900 tracking-tight">Access Protocol Rejected</h3>
               <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-2 max-w-sm mx-auto">
                 {isGlobalSessionActive 
                  ? `The feedback session for ${user.department} - ${user.semester} has been stopped by Admin.` 
                  : "The global feedback protocol is currently locked for maintenance."}
               </p>
             </div>
          </div>
        ) : (
          <form onSubmit={handleSubmit} className="divide-y divide-slate-100">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50/50">
                  <tr>
                    <th className="p-8 text-[11px] font-black text-slate-400 uppercase tracking-widest min-w-[400px]">Assessment Attribute</th>
                    {activeSubjects.map(s => (
                      <th key={s.id} className="p-8 text-center border-l border-slate-100">
                        <div className="flex flex-col items-center gap-1">
                          <span className="text-xs font-black text-slate-900 uppercase tracking-tight">{s.id}</span>
                          <span className="text-[9px] font-bold text-blue-600 uppercase truncate max-w-[100px]">{mappedFacultyForSubject(s.id)}</span>
                        </div>
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {metrics.map((metric, mIdx) => (
                    <tr key={mIdx} className="hover:bg-slate-50/30 transition-colors">
                      <td className="p-8 text-sm font-bold text-slate-700 leading-relaxed">{metric}</td>
                      {activeSubjects.map(s => (
                        <td key={s.id} className="p-8 text-center border-l border-slate-100">
                          <select 
                            required
                            value={matrixScores[s.id]?.[mIdx] || ''} 
                            onChange={(e) => setMatrixScores({...matrixScores, [s.id]: {...(matrixScores[s.id]||{}), [mIdx]: parseInt(e.target.value)}})}
                            className={`w-12 h-12 rounded-xl border-2 text-center font-black transition-all appearance-none cursor-pointer ${matrixScores[s.id]?.[mIdx] ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-slate-50 border-slate-200 text-slate-400'}`}
                          >
                            <option value="">-</option>
                            {[5, 4, 3, 2, 1].map(n => <option key={n} value={n}>{n}</option>)}
                          </select>
                        </td>
                      ))}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            <div className="p-10 bg-white space-y-8">
              <div className="flex items-start gap-4 p-6 bg-blue-50 border border-blue-100 rounded-3xl">
                <ShieldCheck className="text-blue-600 shrink-0" size={24} />
                <p className="text-[11px] font-bold text-blue-700 leading-relaxed">
                  ZK-PROOF INTEGRITY: Your selections are hashed locally before transmission. Neither the Faculty nor the Admin can trace these specific scores back to your identifier.
                </p>
              </div>
              <textarea 
                value={suggestions} 
                onChange={(e) => setSuggestions(e.target.value)} 
                placeholder="Improvement suggestions for assigned faculty (Optional)..." 
                className="w-full p-8 bg-slate-50 border-2 border-slate-100 rounded-[2.5rem] min-h-[120px] font-bold text-sm outline-none focus:border-blue-600 transition-all shadow-inner"
              />
              <button type="submit" disabled={isSubmitting} className="w-full py-8 bg-slate-900 text-white rounded-[2.5rem] font-black uppercase tracking-widest text-xs flex items-center justify-center gap-4 transition-all active:scale-95 disabled:opacity-50 shadow-2xl">
                {isSubmitting ? <><Loader2 className="animate-spin" /> Anchoring Scores...</> : <><Send size={20} /> Finalize & Submit Bundle</>}
              </button>
            </div>
          </form>
        )}
      </div>
    </div>
  );
};

export default FeedbackPortal;

import React, { useState, useEffect } from 'react';
import { 
  FileText, 
  BarChart3, 
  Lock,
  UserCheck
} from 'lucide-react';
import FeedbackPortal from './components/FeedbackPortal';
import AnalysisView from './components/AnalysisView';
import AdminDashboard from './components/AdminDashboard';
import FacultyResultsView from './components/FacultyResultsView';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Auth from './components/Auth';
import ProtectedAdminRoute from './components/ProtectedAdminRoute';
import { FeedbackEntry, User, UserRole, Subject, Faculty, Department, ArchiveRecord } from './types';
import { 
  SUBJECTS as INITIAL_SUBJECTS, 
  FACULTY_DATA as INITIAL_FACULTIES,
  THEORY_METRICS as INITIAL_THEORY_METRICS,
  LAB_METRICS as INITIAL_LAB_METRICS,
  DEPARTMENTS,
  SEMESTERS
} from './constants';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<string>('feedback');
  const [feedbacks, setFeedbacks] = useState<FeedbackEntry[]>([]);
  const [archives, setArchives] = useState<ArchiveRecord[]>([]);
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [isGlobalSessionActive, setIsGlobalSessionActive] = useState(true);

  const [subjects, setSubjects] = useState<Subject[]>(INITIAL_SUBJECTS);
  const [faculties, setFaculties] = useState<Faculty[]>(INITIAL_FACULTIES);

  const [theoryQuestions, setTheoryQuestions] = useState<Record<Department, string[]>>(
    DEPARTMENTS.reduce((acc, dept) => ({ ...acc, [dept]: [...INITIAL_THEORY_METRICS] }), {} as Record<Department, string[]>)
  );
  const [labQuestions, setLabQuestions] = useState<Record<Department, string[]>>(
    DEPARTMENTS.reduce((acc, dept) => ({ ...acc, [dept]: [...INITIAL_LAB_METRICS] }), {} as Record<Department, string[]>)
  );

  const [sessionRegistry, setSessionRegistry] = useState<Record<string, boolean>>(
    DEPARTMENTS.reduce((acc, dept) => {
      SEMESTERS.forEach(sem => { acc[`${dept}-${sem}`] = true; });
      return acc;
    }, {} as Record<string, boolean>)
  );

  const archiveSession = () => {
    // Hybrid logic: Move current state to PostgreSQL/Archive and reset blockchain node
    const newArchives: ArchiveRecord[] = faculties.map(f => ({
      sessionId: `2025_SEM1_${Date.now()}`,
      year: '2025',
      facultyId: f.id,
      dept: f.department,
      avgRating: 17.5 + (Math.random() * 2),
      semester: '3.1'
    }));
    setArchives([...archives, ...newArchives]);
    setFeedbacks([]); // Reset active feedbacks for new session
    alert("Session Archived. Current data moved to Persistence Layer.");
  };

  const handleAuth = (authenticatedUser: User) => {
    setUser(authenticatedUser);
    if (authenticatedUser.role === UserRole.ADMIN) setActiveTab('admin');
    else if (authenticatedUser.role === UserRole.FACULTY) setActiveTab('faculty_results');
    else setActiveTab('feedback');
  };

  if (!user) return <Auth onAuthenticate={handleAuth} />;

  const tabs = [
    { id: 'feedback', label: 'Vote Feedback', icon: FileText, roles: [UserRole.STUDENT] },
    { id: 'faculty_results', label: 'Performance', icon: UserCheck, roles: [UserRole.FACULTY] },
    { id: 'analysis', label: 'Analytics', icon: BarChart3, roles: [UserRole.FACULTY, UserRole.ADMIN] },
    { id: 'admin', label: 'Super-Admin', icon: Lock, roles: [UserRole.ADMIN] },
  ].filter(tab => !tab.roles || tab.roles.includes(user.role));

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-inter">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} tabs={tabs} isOpen={isSidebarOpen} toggleSidebar={() => setSidebarOpen(!isSidebarOpen)} user={user} onLogout={() => setUser(null)} />
      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <Header activeTab={tabs.find(t => t.id === activeTab)?.label || 'SRK-IT'} user={user} />
        <main className="flex-1 overflow-y-auto p-4 md:p-8">
          <div className="max-w-7xl mx-auto space-y-6">
            {activeTab === 'feedback' && (
              <FeedbackPortal 
                onSubmit={(e) => setFeedbacks([...feedbacks, e])} 
                onLogout={() => setUser(null)} 
                user={user} 
                subjects={subjects} 
                faculties={faculties}
                sessionRegistry={sessionRegistry} 
                theoryQuestions={theoryQuestions} 
                labQuestions={labQuestions} 
                isGlobalSessionActive={isGlobalSessionActive} 
              />
            )}
            {activeTab === 'faculty_results' && <FacultyResultsView user={user} feedbacks={feedbacks} faculties={faculties} subjects={subjects} />}
            {activeTab === 'analysis' && <AnalysisView feedbacks={feedbacks} user={user} />}
            {activeTab === 'admin' && (
              <ProtectedAdminRoute user={user}>
                <AdminDashboard 
                  subjects={subjects} setSubjects={setSubjects}
                  faculties={faculties} setFaculties={setFaculties}
                  sessionRegistry={sessionRegistry} setSessionRegistry={setSessionRegistry}
                  theoryQuestions={theoryQuestions} setTheoryQuestions={setTheoryQuestions}
                  labQuestions={labQuestions} setLabQuestions={setLabQuestions}
                  isGlobalSessionActive={isGlobalSessionActive} setIsGlobalSessionActive={setIsGlobalSessionActive}
                  user={user} feedbacks={feedbacks} archives={archives} onArchiveSession={archiveSession}
                />
              </ProtectedAdminRoute>
            )}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

