import { 
  Shield, 
  User, 
  GraduationCap, 
  LockKeyhole,
  KeyRound,
  IdCard,
  Building2,
  Presentation,
  CheckCircle2,
  Users,
  Briefcase,
  ChevronDown
} from 'lucide-react';
import { UserRole, User as UserType, Department, Semester } from '../types';
import { DEPARTMENTS, SEMESTERS } from '../constants';

const SUPER_ADMIN_CREDS = {
  email: "admin@gmail.com",
  password: "123456"
};

interface AuthProps {
  onAuthenticate: (user: UserType) => void;
}

const Auth: React.FC<AuthProps> = ({ onAuthenticate }) => {
  const [role, setRole] = useState<UserRole>(UserRole.STUDENT);
  const [dept, setDept] = useState<Department>('CSE');
  const [sem, setSem] = useState<Semester>('3.1');
  const [error, setError] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    fullName: '',
    identifier: '',
    password: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    const emailInput = formData.identifier.trim().toLowerCase();
    const passwordInput = formData.password.trim();

    // Admin Auth Logic
    if (role === UserRole.ADMIN) {
      if (emailInput === SUPER_ADMIN_CREDS.email && passwordInput === SUPER_ADMIN_CREDS.password) {
        onAuthenticate({
          fullName: "System Admin",
          email: SUPER_ADMIN_CREDS.email,
          role: UserRole.ADMIN,
          isAuthorized: true
        });
        return;
      }
      setError("Root access denied. Invalid Super-Admin credentials.");
      return;
    }

    // HOD Auth Logic (Mocking status - actual status handled in App state)
    if (role === UserRole.HOD) {
       onAuthenticate({
          fullName: formData.fullName || "HOD User",
          email: emailInput,
          role: UserRole.HOD,
          department: dept,
          isAuthorized: false // Defaults to false, Admin must grant access
       });
       return;
    }

    // Student/Faculty Auth Logic
    onAuthenticate({
      fullName: formData.fullName || (role === UserRole.STUDENT ? "Anonymous Student" : "Faculty Node"),
      email: emailInput,
      role: role,
      department: dept,
      semester: role === UserRole.STUDENT ? sem : undefined,
      facultyId: role === UserRole.FACULTY ? 'F001' : undefined,
      isAuthorized: true // Students/Faculty don't need manual "Admin" approval to see their basic dash
    });
  };

  return (
    <div className="flex min-h-screen bg-slate-50 items-center justify-center p-6 font-inter">
      <div className="w-full max-w-lg space-y-8">
        <div className="text-center">
          <div className="mx-auto w-20 h-20 bg-slate-900 rounded-[2rem] flex items-center justify-center text-white shadow-2xl mb-6 transform hover:rotate-12 transition-transform">
            <Shield size={40} />
          </div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tight uppercase">SRK-IT Portal</h2>
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.3em] mt-2">Decentralized Governance Node</p>
        </div>

        <div className="bg-white p-10 md:p-12 rounded-[3.5rem] border border-slate-200 shadow-2xl space-y-8 relative overflow-hidden">
          {error && (
            <div className="p-4 bg-red-50 text-red-600 text-xs font-black rounded-2xl border border-red-100 flex items-center gap-2 animate-in slide-in-from-top-4">
              <LockKeyhole size={14} /> {error}
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Access Role</label>
              <div className="relative">
                <Users size={18} className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 pointer-events-none" />
                <select 
                  value={role} 
                  onChange={(e) => setRole(e.target.value as UserRole)}
                  className="w-full pl-14 pr-10 py-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm outline-none appearance-none focus:border-slate-900 transition-all cursor-pointer"
                >
                  <option value={UserRole.STUDENT}>Student Node</option>
                  <option value={UserRole.FACULTY}>Faculty Node</option>
                  <option value={UserRole.HOD}>Head of Dept (HOD)</option>
                  <option value={UserRole.ADMIN}>Super-Admin</option>
                </select>
                <ChevronDown size={16} className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" />
              </div>
            </div>

            {role !== UserRole.ADMIN && (
              <div className="grid grid-cols-2 gap-4 animate-in fade-in duration-300">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Academic Unit</label>
                  <div className="relative">
                    <Building2 size={16} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" />
                    <select 
                      value={dept} 
                      onChange={(e) => setDept(e.target.value as Department)} 
                      className="w-full pl-12 pr-4 py-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-xs outline-none focus:border-slate-900"
                    >
                      {DEPARTMENTS.map(d => <option key={d} value={d}>{d}</option>)}
                    </select>
                  </div>
                </div>
                {role === UserRole.STUDENT && (
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Semester</label>
                    <select 
                      value={sem} 
                      onChange={(e) => setSem(e.target.value as Semester)} 
                      className="w-full px-4 py-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-xs outline-none focus:border-slate-900"
                    >
                      {SEMESTERS.map(s => <option key={s} value={s}>{s}</option>)}
                    </select>
                  </div>
                )}
              </div>
            )}

            {role !== UserRole.ADMIN && (
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Legal Full Name</label>
                <div className="relative">
                  <User size={18} className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300" />
                  <input 
                    type="text" 
                    required 
                    value={formData.fullName} 
                    onChange={(e) => setFormData({...formData, fullName: e.target.value})} 
                    placeholder="e.g. Ramesh Babu" 
                    className="w-full pl-14 pr-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm outline-none focus:border-slate-900 transition-all" 
                  />
                </div>
              </div>
            )}

            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Login Identifier</label>
              <div className="relative">
                <IdCard size={18} className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300" />
                <input 
                  type="text" 
                  required 
                  value={formData.identifier} 
                  onChange={(e) => setFormData({...formData, identifier: e.target.value})} 
                  placeholder={role === UserRole.ADMIN ? "admin@gmail.com" : "Email / Roll No"} 
                  className="w-full pl-14 pr-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm outline-none focus:border-slate-900 transition-all" 
                />
              </div>
            </div>

            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Secure Password</label>
              <div className="relative">
                <KeyRound size={18} className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300" />
                <input 
                  type="password" 
                  required 
                  value={formData.password} 
                  onChange={(e) => setFormData({...formData, password: e.target.value})} 
                  placeholder="••••••••" 
                  className="w-full pl-14 pr-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm outline-none focus:border-slate-900 transition-all" 
                />
              </div>
            </div>

            <button 
              type="submit" 
              className="w-full py-6 bg-slate-900 text-white rounded-[2rem] font-black uppercase tracking-widest text-[11px] shadow-2xl flex items-center justify-center gap-3 transition-all hover:bg-slate-800 active:scale-[0.98] group"
            >
              Verify Identity <CheckCircle2 size={18} className="group-hover:translate-x-1 transition-transform" />
            </button>
          </form>
          <div className="pt-4 text-center">
            <p className="text-[9px] font-black text-slate-300 uppercase tracking-widest">Quantum-Resistant Encryption Node Protocol v4.2.1</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Auth;

import React, { useState } from 'react';
import { 
  Users, 
  Database, 
  Zap, 
  Power, 
  Hash, 
  Filter, 
  Plus, 
  RefreshCcw, 
  Archive, 
  FileText, 
  TrendingUp,
  Download,
  ShieldCheck,
  Search,
  Settings2,
  ShieldAlert,
  UserCheck,
  UserX
} from 'lucide-react';
import { Faculty, Subject, FeedbackEntry, User, Department, ArchiveRecord, UserRole } from '../types';
import FacultyControl from './FacultyControl';
import DatasetManager from './DatasetManager';
import AttributeEditor from './AttributeEditor';
import RecordsArchive from './RecordsArchive';
import SessionManager from './SessionManager';

interface AdminDashboardProps {
  subjects: Subject[];
  setSubjects: React.Dispatch<React.SetStateAction<Subject[]>>;
  faculties: Faculty[];
  setFaculties: React.Dispatch<React.SetStateAction<Faculty[]>>;
  sessionRegistry: Record<string, boolean>;
  setSessionRegistry: React.Dispatch<React.SetStateAction<Record<string, boolean>>>;
  theoryQuestions: Record<Department, string[]>;
  setTheoryQuestions: React.Dispatch<React.SetStateAction<Record<Department, string[]>>>;
  labQuestions: Record<Department, string[]>;
  setLabQuestions: React.Dispatch<React.SetStateAction<Record<Department, string[]>>>;
  isGlobalSessionActive: boolean;
  setIsGlobalSessionActive: (val: boolean) => void;
  user: User;
  feedbacks: FeedbackEntry[];
  archives: ArchiveRecord[];
  onArchiveSession: () => void;
  hods: User[];
  onUpdateHOD: (email: string, isAuthorized: boolean) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  faculties, setFaculties,
  sessionRegistry, setSessionRegistry,
  isGlobalSessionActive, setIsGlobalSessionActive,
  feedbacks,
  theoryQuestions, setTheoryQuestions,
  labQuestions, setLabQuestions,
  archives,
  onArchiveSession,
  hods,
  onUpdateHOD
}) => {
  const [activeSubTab, setActiveSubTab] = useState<string>('bulk');

  const handleUpdateQuestions = (type: 'THEORY' | 'LAB', questions: string[]) => {
    if (type === 'THEORY') {
      setTheoryQuestions(prev => {
        const next = { ...prev };
        Object.keys(next).forEach(dept => { next[dept as Department] = [...questions]; });
        return next;
      });
    } else {
      setLabQuestions(prev => {
        const next = { ...prev };
        Object.keys(next).forEach(dept => { next[dept as Department] = [...questions]; });
        return next;
      });
    }
  };

  const handleBulkSync = (rawData: string) => {
    console.log("Processing bulk sync for:", rawData);
    alert("Global Registry Synchronized via Blockchain Node.");
  };

  const handleToggleSession = (key: string) => {
    setSessionRegistry(prev => ({
      ...prev,
      [key]: !prev[key]
    }));
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20">
      {/* Super-Admin Toolbar */}
      <div className="flex flex-wrap items-center gap-2 bg-slate-900 p-2 rounded-[2.5rem] border border-slate-800 shadow-2xl overflow-x-auto no-scrollbar">
        {[
          { id: 'bulk', icon: Database, label: 'Bulk Intake' },
          { id: 'faculty', icon: Users, label: 'Faculty Nodes' },
          { id: 'hods', icon: ShieldAlert, label: 'HOD Control' },
          { id: 'sessions', icon: Settings2, label: 'Session Control' },
          { id: 'attributes', icon: Zap, label: 'Attribute Control' },
          { id: 'archives', icon: Archive, label: 'Records Archive' },
          { id: 'reports', icon: TrendingUp, label: 'HOD Reports' },
        ].map(tab => (
          <button 
            key={tab.id}
            onClick={() => setActiveSubTab(tab.id)} 
            className={`flex items-center gap-2 px-6 py-3 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${activeSubTab === tab.id ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/20' : 'text-slate-500 hover:text-white'}`}
          >
            <tab.icon size={14} /> {tab.label}
          </button>
        ))}

        <div className="ml-auto pr-2 flex items-center gap-2">
          <button 
            onClick={onArchiveSession}
            className="flex items-center gap-2 px-5 py-3 bg-indigo-600 text-white rounded-full text-[10px] font-black uppercase tracking-widest hover:bg-indigo-700 transition-all"
          >
            <ShieldCheck size={14} /> Archive Session
          </button>
          <button 
            onClick={() => setIsGlobalSessionActive(!isGlobalSessionActive)}
            className={`flex items-center gap-2 px-6 py-3 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${isGlobalSessionActive ? 'bg-emerald-600 text-white' : 'bg-red-600 text-white shadow-lg shadow-red-500/20'}`}
          >
            <Power size={14} /> {isGlobalSessionActive ? 'Sessions Active' : 'Global Lock'}
          </button>
        </div>
      </div>

      <div className="mt-8">
        {activeSubTab === 'bulk' && (
          <DatasetManager 
            theoryQuestions={theoryQuestions}
            labQuestions={labQuestions}
            onUpdateQuestions={handleUpdateQuestions}
            onBulkSync={handleBulkSync}
          />
        )}

        {activeSubTab === 'faculty' && (
          <FacultyControl 
            faculties={faculties} 
            onUpdateFaculty={(f) => setFaculties(prev => prev.map(p => p.id === f.id ? f : p))}
            onAddFaculty={(f) => setFaculties(prev => [...prev, f])}
          />
        )}

        {activeSubTab === 'sessions' && (
          <SessionManager 
            sessionRegistry={sessionRegistry}
            onToggleSession={handleToggleSession}
          />
        )}

        {activeSubTab === 'hods' && (
          <div className="bg-white p-12 rounded-[4rem] border border-slate-200 shadow-sm space-y-10 animate-in fade-in">
            <div>
              <h3 className="text-2xl font-black uppercase tracking-tight">HOD Authorization Hub</h3>
              <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">Grant or Revoke Admin-Lite Permissions for Departmental Heads</p>
            </div>

            <div className="grid grid-cols-1 gap-4">
              {hods.map(hod => (
                <div key={hod.email} className="flex items-center justify-between p-6 bg-slate-50 border border-slate-100 rounded-3xl hover:bg-slate-100 transition-all">
                  <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black text-white ${hod.isAuthorized ? 'bg-emerald-500 shadow-lg shadow-emerald-500/20' : 'bg-slate-400'}`}>
                      {hod.fullName.charAt(0)}
                    </div>
                    <div>
                      <h4 className="font-black text-slate-900 uppercase text-sm tracking-tight">{hod.fullName}</h4>
                      <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">{hod.department} • {hod.email}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-3">
                    <span className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest ${hod.isAuthorized ? 'bg-emerald-100 text-emerald-600' : 'bg-amber-100 text-amber-600'}`}>
                      {hod.isAuthorized ? 'HOD_ACTIVE' : 'HOD_PENDING'}
                    </span>
                    <button 
                      onClick={() => onUpdateHOD(hod.email, !hod.isAuthorized)}
                      className={`flex items-center gap-2 px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all active:scale-95 ${hod.isAuthorized ? 'bg-red-50 text-red-600 hover:bg-red-100' : 'bg-emerald-600 text-white hover:bg-emerald-700 shadow-xl shadow-emerald-900/10'}`}
                    >
                      {hod.isAuthorized ? <><UserX size={14} /> Revoke Access</> : <><UserCheck size={14} /> Grant Access</>}
                    </button>
                  </div>
                </div>
              ))}
              {hods.length === 0 && (
                <div className="p-20 text-center border-2 border-dashed border-slate-100 rounded-[3rem] text-slate-300 font-black uppercase text-[10px] tracking-widest">
                  No HOD Nodes Registered in Registry
                </div>
              )}
            </div>
          </div>
        )}

        {activeSubTab === 'attributes' && (
          <AttributeEditor 
            theoryQuestions={theoryQuestions} 
            labQuestions={labQuestions}
            setTheoryQuestions={setTheoryQuestions}
            setLabQuestions={setLabQuestions}
          />
        )}

        {activeSubTab === 'archives' && (
          <RecordsArchive archives={archives} faculties={faculties} />
        )}

        {activeSubTab === 'reports' && (
          <div className="bg-white p-12 rounded-[3rem] border border-slate-200 shadow-sm space-y-8 animate-in zoom-in">
             <div className="flex justify-between items-center">
               <div>
                  <h3 className="text-2xl font-black uppercase tracking-tight">Departmental Governance Hub</h3>
                  <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">HOD-Level Performance Visibility (Read Only)</p>
               </div>
               <button className="flex items-center gap-2 px-6 py-3 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase"><Download size={14}/> Export Audits</button>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                {['CSE', 'ECE', 'EEE', 'IT', 'MBA'].map(dept => (
                  <div key={dept} className="p-8 bg-slate-50 border border-slate-100 rounded-[2.5rem] group hover:bg-slate-900 hover:text-white transition-all duration-500 cursor-pointer">
                     <TrendingUp className="text-blue-500 mb-4 group-hover:text-white" size={32} />
                     <h4 className="text-xl font-black">{dept} Dept</h4>
                     <p className="text-[10px] font-black uppercase mt-1 opacity-50">View Aggregated Analytics</p>
                  </div>
                ))}
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect } from 'react';
import { 
  FileText, 
  BarChart3, 
  Lock,
  UserCheck,
  Building2
} from 'lucide-react';
import FeedbackPortal from './components/FeedbackPortal';
import AnalysisView from './components/AnalysisView';
import AdminDashboard from './components/AdminDashboard';
import FacultyResultsView from './components/FacultyResultsView';
import HODDashboard from './components/HODDashboard';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Auth from './components/Auth';
import ProtectedAdminRoute from './components/ProtectedAdminRoute';
import { FeedbackEntry, User, UserRole, Subject, Faculty, Department, ArchiveRecord } from './types';
import { 
  SUBJECTS as INITIAL_SUBJECTS, 
  FACULTY_DATA as INITIAL_FACULTIES,
  THEORY_METRICS as INITIAL_THEORY_METRICS,
  LAB_METRICS as INITIAL_LAB_METRICS,
  DEPARTMENTS,
  SEMESTERS
} from './constants';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<string>('feedback');
  const [feedbacks, setFeedbacks] = useState<FeedbackEntry[]>([]);
  const [archives, setArchives] = useState<ArchiveRecord[]>([]);
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [isGlobalSessionActive, setIsGlobalSessionActive] = useState(true);

  const [subjects, setSubjects] = useState<Subject[]>(INITIAL_SUBJECTS);
  const [faculties, setFaculties] = useState<Faculty[]>(INITIAL_FACULTIES);

  // State for HOD Management
  const [hods, setHods] = useState<User[]>([
    { fullName: 'Radhika K.', email: 'radhika@srkit.edu.in', role: UserRole.HOD, department: 'CSE', isAuthorized: true },
    { fullName: 'Sudharani M.', email: 'sudharani@srkit.edu.in', role: UserRole.HOD, department: 'MBA', isAuthorized: false }
  ]);

  const [theoryQuestions, setTheoryQuestions] = useState<Record<Department, string[]>>(
    DEPARTMENTS.reduce((acc, dept) => ({ ...acc, [dept]: [...INITIAL_THEORY_METRICS] }), {} as Record<Department, string[]>)
  );
  const [labQuestions, setLabQuestions] = useState<Record<Department, string[]>>(
    DEPARTMENTS.reduce((acc, dept) => ({ ...acc, [dept]: [...INITIAL_LAB_METRICS] }), {} as Record<Department, string[]>)
  );

  const [sessionRegistry, setSessionRegistry] = useState<Record<string, boolean>>(
    DEPARTMENTS.reduce((acc, dept) => {
      SEMESTERS.forEach(sem => { acc[`${dept}-${sem}`] = true; });
      return acc;
    }, {} as Record<string, boolean>)
  );

  const archiveSession = () => {
    const newArchives: ArchiveRecord[] = faculties.map(f => ({
      sessionId: `2025_SEM1_${Date.now()}`,
      year: '2025',
      facultyId: f.id,
      dept: f.department,
      avgRating: 17.5 + (Math.random() * 2),
      semester: '3.1'
    }));
    setArchives([...archives, ...newArchives]);
    setFeedbacks([]);
    alert("Session Archived Successfully.");
  };

  const handleUpdateHOD = (email: string, isAuthorized: boolean) => {
    setHods(prev => prev.map(hod => hod.email === email ? { ...hod, isAuthorized } : hod));
    // If the currently logged in user is this HOD, update their local user state too
    if (user && user.email === email) {
      setUser({ ...user, isAuthorized });
    }
  };

  const handleAuth = (authenticatedUser: User) => {
    // Recheck HOD authorization from master list if it's an HOD login
    if (authenticatedUser.role === UserRole.HOD) {
      const existing = hods.find(h => h.email === authenticatedUser.email);
      if (existing) {
        authenticatedUser.isAuthorized = existing.isAuthorized;
      } else {
        // First time HOD login - add to registry as pending
        setHods(prev => [...prev, authenticatedUser]);
      }
    }

    setUser(authenticatedUser);
    if (authenticatedUser.role === UserRole.ADMIN) setActiveTab('admin');
    else if (authenticatedUser.role === UserRole.FACULTY) setActiveTab('faculty_results');
    else if (authenticatedUser.role === UserRole.HOD) setActiveTab('hod_dashboard');
    else setActiveTab('feedback');
  };

  if (!user) return <Auth onAuthenticate={handleAuth} />;

  const tabs = [
    { id: 'feedback', label: 'Vote Feedback', icon: FileText, roles: [UserRole.STUDENT] },
    { id: 'faculty_results', label: 'Performance', icon: UserCheck, roles: [UserRole.FACULTY] },
    { id: 'hod_dashboard', label: 'HOD Hub', icon: Building2, roles: [UserRole.HOD] },
    { id: 'analysis', label: 'Analytics', icon: BarChart3, roles: [UserRole.FACULTY, UserRole.ADMIN, UserRole.HOD] },
    { id: 'admin', label: 'Super-Admin', icon: Lock, roles: [UserRole.ADMIN] },
  ].filter(tab => !tab.roles || tab.roles.includes(user.role));

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-inter">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} tabs={tabs} isOpen={isSidebarOpen} toggleSidebar={() => setSidebarOpen(!isSidebarOpen)} user={user} onLogout={() => setUser(null)} />
      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <Header activeTab={tabs.find(t => t.id === activeTab)?.label || 'SRK-IT'} user={user} />
        <main className="flex-1 overflow-y-auto p-4 md:p-8">
          <div className="max-w-7xl mx-auto space-y-6">
            {activeTab === 'feedback' && (
              <FeedbackPortal 
                onSubmit={(e) => setFeedbacks([...feedbacks, e])} 
                onLogout={() => setUser(null)} 
                user={user} 
                subjects={subjects} 
                faculties={faculties}
                sessionRegistry={sessionRegistry} 
                theoryQuestions={theoryQuestions} 
                labQuestions={labQuestions} 
                isGlobalSessionActive={isGlobalSessionActive} 
              />
            )}
            {activeTab === 'faculty_results' && <FacultyResultsView user={user} feedbacks={feedbacks} faculties={faculties} subjects={subjects} />}
