import React, { useState, useRef } from 'react';
import { Database, Zap, FileText, Settings, Save, RefreshCw, AlertTriangle, CheckCircle2, Upload, Plus, FileType, AlertCircle } from 'lucide-react';
import { Department } from '../types';
import Papa from 'papaparse';
import * as XLSX from 'xlsx';

interface DatasetManagerProps {
  theoryQuestions: Record<Department, string[]>;
  labQuestions: Record<Department, string[]>;
  onUpdateQuestions: (type: 'THEORY' | 'LAB', questions: string[]) => void;
  onBulkSync: (rawData: string) => void;
}

const DatasetManager: React.FC<DatasetManagerProps> = ({ 
  theoryQuestions, 
  labQuestions, 
  onUpdateQuestions,
  onBulkSync
}) => {
  const [rawData, setRawData] = useState('');
  const [isSyncing, setIsSyncing] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const processFile = (file: File) => {
    setErrorMsg(null);
    const extension = file.name.split('.').pop()?.toLowerCase();

    if (extension === 'csv') {
      Papa.parse(file, {
        header: true,
        skipEmptyLines: true,
        complete: (results) => {
          if (results.errors.length > 0) {
            setErrorMsg("Error parsing CSV. Please check formatting.");
          } else {
            setRawData(JSON.stringify(results.data, null, 2));
          }
        }
      });
    } else if (extension === 'json') {
      const reader = new FileReader();
      reader.onload = (e) => {
        try {
          const json = JSON.parse(e.target?.result as string);
          setRawData(JSON.stringify(json, null, 2));
        } catch {
          setErrorMsg("Invalid JSON file.");
        }
      };
      reader.readAsText(file);
    } else if (['xlsx', 'xls'].includes(extension || '')) {
      const reader = new FileReader();
      reader.onload = (e) => {
        try {
          const data = new Uint8Array(e.target?.result as ArrayBuffer);
          const workbook = XLSX.read(data, { type: 'array' });
          const firstSheet = workbook.SheetNames[0];
          const worksheet = workbook.Sheets[firstSheet];
          const json = XLSX.utils.sheet_to_json(worksheet);
          setRawData(JSON.stringify(json, null, 2));
        } catch {
          setErrorMsg("Error parsing Excel file.");
        }
      };
      reader.readAsArrayBuffer(file);
    } else {
      setErrorMsg("Unsupported file format. Use CSV, XLSX, or JSON.");
    }
  };

  const handleSyncClick = () => {
    if (!rawData.trim()) return;
    setIsSyncing(true);
    onBulkSync(rawData);
    setTimeout(() => {
      setIsSyncing(false);
      setRawData('');
    }, 2000);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) processFile(file);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = () => {
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files?.[0];
    if (file) processFile(file);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="bg-white p-10 rounded-[3rem] border border-slate-200 shadow-sm space-y-6">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-blue-100 text-blue-600 rounded-2xl">
              <Database size={24} />
            </div>
            <div>
              <h3 className="text-xl font-black text-slate-900 uppercase tracking-tight">Universal Bulk Intake</h3>
              <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mt-1">Ingest CSV, XLSX, or JSON Registry Payloads</p>
            </div>
          </div>
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="p-4 bg-slate-100 text-slate-600 rounded-2xl hover:bg-blue-600 hover:text-white transition-all shadow-sm"
            title="Open File Explorer"
          >
            <Plus size={24} />
          </button>
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileUpload} 
            accept=".csv, .json, .xlsx, .xls" 
            className="hidden" 
          />
        </div>

        {errorMsg && (
          <div className="p-4 bg-red-50 text-red-600 rounded-2xl border border-red-100 flex items-center gap-2 text-xs font-bold animate-in slide-in-from-top-2">
            <AlertCircle size={16} /> {errorMsg}
          </div>
        )}

        <div 
          onDragOver={handleDragOver}
          onDragLeave={handleDragLeave}
          onDrop={handleDrop}
          className={`relative group transition-all ${isDragging ? 'scale-[1.02]' : ''}`}
        >
          <textarea 
            value={rawData}
            onChange={(e) => setRawData(e.target.value)}
            placeholder="Paste raw data or drag & drop CSV/XLSX/JSON..."
            className={`w-full h-64 p-8 bg-slate-50 border-2 border-dashed rounded-[2.5rem] font-mono text-xs outline-none transition-all resize-none ${
              isDragging ? 'border-blue-500 bg-blue-50/30' : 'border-slate-200 focus:border-blue-500 focus:bg-white'
            }`}
          />
          {(!rawData && !isDragging) && (
            <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none text-slate-300">
              <FileType size={48} className="mb-4 opacity-20" />
              <p className="font-black uppercase text-[10px] tracking-[0.3em]">Drop Registry File Here</p>
              <p className="text-[8px] mt-2 uppercase opacity-50">CSV • XLSX • JSON</p>
            </div>
          )}
        </div>

        <div className="flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-2 text-amber-600 font-bold text-[10px] uppercase tracking-widest bg-amber-50 px-4 py-2 rounded-xl">
            <AlertTriangle size={14} /> Validation: Headers must match SRK Schema
          </div>
          <div className="flex gap-3">
             <button 
              onClick={() => { setRawData(''); setErrorMsg(null); }}
              className="px-6 py-5 bg-slate-100 text-slate-500 rounded-[1.5rem] font-black uppercase text-xs tracking-widest hover:bg-slate-200 transition-all"
            >
              Clear Buffer
            </button>
            <button 
              onClick={handleSyncClick}
              disabled={isSyncing || !rawData.trim()}
              className="flex items-center gap-3 px-10 py-5 bg-slate-900 text-white rounded-[1.5rem] font-black uppercase text-xs tracking-widest shadow-xl disabled:opacity-50 active:scale-95 transition-all"
            >
              {isSyncing ? <RefreshCw className="animate-spin" size={18} /> : <Zap size={18} />} Run Global Sync
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

