// Programmatically generate initial subjects for all departments and semesters to ensure coverage
const generateInitialSubjects = (): Subject[] => {
  const subs: Subject[] = [];
  DEPARTMENTS.forEach(dept => {
    SEMESTERS.forEach(sem => {
      // Create 5 Theory subjects for each sem
      for (let i = 1; i <= 5; i++) {
        subs.push({
          id: `${dept}-${sem}-S${i}`,
          name: `${dept} Subject ${i}`,
          code: `${dept}-S${i}`,
          department: dept,
          semester: sem,
          type: FeedbackType.THEORY
        });
