  DEPARTMENTS.forEach(dept => {
    // We'll create 10 faculty per department and distribute subjects
    for (let i = 1; i <= 10; i++) {
      const id = `F${facIdCounter.toString().padStart(4, '0')}`;
      const deptSubjects = SUBJECTS.filter(s => s.department === dept).map(s => s.id);

      // Each faculty takes a chunk of subjects for this department
      const startIndex = (i - 1) * 5;
      const assigned = deptSubjects.slice(startIndex, startIndex + 10); // Overlap subjects for variety

      facs.push({
        id,
        name: `Faculty ${facIdCounter}`,
        department: dept,
        subjects: assigned,
        designation: i % 2 === 0 ? 'Professor' : 'Assistant Professor'
      });
      facIdCounter++;
    }
  });

  return facs;
};

