// Programmatically generate initial subjects for all departments and semesters to ensure coverage
const generateInitialSubjects = (): Subject[] => {
  const subs: Subject[] = [];
  DEPARTMENTS.forEach(dept => {
    SEMESTERS.forEach(sem => {
      // Create 5 Theory subjects for each sem
      for (let i = 1; i <= 5; i++) {
        subs.push({
          id: `${dept}-${sem}-S${i}`,
          name: `${dept} Subject ${i}`,
          code: `${dept}-S${i}`,
          department: dept,
          semester: sem,
          type: FeedbackType.THEORY
        });
      }
      // Create 2 Lab subjects for each sem
      for (let i = 1; i <= 2; i++) {
        subs.push({
          id: `${dept}-${sem}-L${i}`,
          name: `${dept} Lab ${i}`,
          code: `${dept}-L${i}`,
          department: dept,
          semester: sem,
          type: FeedbackType.LAB
        });
      }
    });
  });
  return subs;
};

export const SUBJECTS: Subject[] = generateInitialSubjects();

// Generate initial faculty mapping for a subset of the generated subjects
const generateInitialFaculty = (): Faculty[] => {
  const facs: Faculty[] = [];
  let facIdCounter = 1;

  DEPARTMENTS.forEach(dept => {
    // We'll create 10 faculty per department and distribute subjects
    for (let i = 1; i <= 10; i++) {
      const id = `F${facIdCounter.toString().padStart(4, '0')}`;
      const deptSubjects = SUBJECTS.filter(s => s.department === dept).map(s => s.id);

      // Each faculty takes a chunk of subjects for this department
      const startIndex = (i - 1) * 5;
      const assigned = deptSubjects.slice(startIndex, startIndex + 10); 

      facs.push({
        id,
        name: `Faculty ${facIdCounter}`,
        department: dept,
        subjects: assigned,
        designation: i % 2 === 0 ? 'Professor' : 'Assistant Professor'
      });
      facIdCounter++;
    }
  });

  return facs;
};

