// 1. HOD Authorization Middleware
const authorizeHOD = (req, res, next) => {
    const { user } = req.session;
    const requestedDept = req.params.dept; // e.g., /api/feedback/CSE

    if (user.role === 'HOD' && user.department === requestedDept) {
        return next();
    }
    return res.status(403).json({ error: "Access Denied: You are only authorized to audit the " + user.department + " cluster." });
};

// 2. Faculty Row-Level Security Middleware
const authorizeFacultyNode = (req, res, next) => {
    const { user } = req.session;
    const requestedFacultyId = req.params.facultyId;

    if (user.role === 'FACULTY' && user.facultyId === requestedFacultyId) {
        return next();
    }
    return res.status(401).json({ error: "Unauthorized Node Query: ID Tampering Detected." });
};
