interface AnalysisViewProps {
  feedbacks: FeedbackEntry[];
  user: User;
}

const AnalysisView: React.FC<AnalysisViewProps> = ({ feedbacks, user }) => {
  // Logic: Lock department if the user is HOD or Faculty. Only Admin can switch branches.
  const isBranchLocked = user.role === UserRole.HOD || user.role === UserRole.FACULTY;
  const initialDept = (isBranchLocked && user.department) ? user.department : (user.department || 'CSE');

  const [selectedDept, setSelectedDept] = useState<Department>(initialDept);
  const [selectedSem, setSelectedSem] = useState<Semester>(user.semester || '1-1');
  const [analysisMode, setAnalysisMode] = useState<'current' | 'historical'>('current');

  const historicalTrends = useMemo(() => [
    { year: '2022', score: 17.4 },
    { year: '2023', score: 18.1 },
    { year: '2024', score: 18.6 }
  ], []);

  const reportData = useMemo(() => {
    return FACULTY_DATA.filter(f => f.department === selectedDept)
      .map((fac, index) => {
        const sub = SUBJECTS.find(s => fac.subjects.includes(s.id) && s.semester === selectedSem);
        if (!sub) return null;

        const relevantFeedbacks = feedbacks.filter(f => f.subjectId === sub.id);
        const realPoints = relevantFeedbacks.reduce((acc, f) => {
           const scores = Object.values(f.data);
           const sum = scores.reduce((s: any, v: any) => s + v, 0) as number;
           return acc + (sum / scores.length);
        }, 0);

        const finalScore = relevantFeedbacks.length > 0 
          ? (realPoints / relevantFeedbacks.length) * 4 
          : 17.5 + (Math.random() * 2);

        return {
          sNo: index + 1,
          faculty: fac.name,
          subject: sub.name,
          points: finalScore,
          dept: selectedDept,
          sem: selectedSem
        };
      }).filter(Boolean);
  }, [selectedDept, selectedSem, feedbacks]);

  const currentHodName = HOD_LIST[selectedDept] || "HOD";

  return (
    <div className="space-y-8 animate-in fade-in duration-700 w-full">
      <div className="flex bg-slate-200 p-1.5 rounded-3xl w-fit mx-auto no-print">
        <button 
          onClick={() => setAnalysisMode('current')} 
          className={`flex items-center gap-2 px-8 py-3 rounded-2xl text-[10px] font-black uppercase transition-all ${analysisMode === 'current' ? 'bg-white shadow-md text-blue-600' : 'text-slate-500'}`}
        >
          <Activity size={14}/> Current Session
        </button>
        <button 
          onClick={() => setAnalysisMode('historical')} 
          className={`flex items-center gap-2 px-8 py-3 rounded-2xl text-[10px] font-black uppercase transition-all ${analysisMode === 'historical' ? 'bg-white shadow-md text-indigo-600' : 'text-slate-500'}`}
        >
          <History size={14}/> Historical Trends
        </button>
      </div>

      {analysisMode === 'historical' ? (
        <div className="bg-white p-12 rounded-[3rem] border border-slate-200 shadow-2xl space-y-10 animate-in zoom-in w-full">
           <div className="flex items-center justify-between">
              <div>
                <h3 className="text-2xl font-black text-slate-900 flex items-center gap-3 uppercase tracking-tight">Performance Evolution</h3>
                <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest mt-1">Audit Trail: 2022 - 2025</p>
              </div>
              <span className="px-5 py-2 bg-indigo-50 text-indigo-600 rounded-2xl text-[10px] font-black uppercase tracking-widest">{selectedDept} Branch Cluster</span>
           </div>
           <div className="h-[450px] w-full">
             <ResponsiveContainer width="100%" height="100%">
               <BarChart data={historicalTrends}>
                 <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                 <XAxis dataKey="year" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12, fontWeight: 700}} />
                 <YAxis domain={[15, 20]} axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12, fontWeight: 700}} />
                 <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)'}} />
                 <Bar dataKey="score" fill="#6366f1" radius={[12, 12, 0, 0]} barSize={84} />
               </BarChart>
             </ResponsiveContainer>
           </div>
           <div className="p-6 bg-slate-50 rounded-3xl border border-slate-100 flex items-start gap-4 text-slate-500">
              <ShieldCheck size={20} className="shrink-0 text-emerald-500" />
              <p className="text-[11px] font-bold leading-relaxed">PROTOCOL: These data nodes represent verified, aggregated ratings anchored to historical blocks. Individual student nullifiers have been purged to ensure permanent anonymity post-session completion.</p>
           </div>
        </div>
      ) : (
        <>
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 no-print w-full">
            <div className="flex items-center gap-3">
              {/* Conditional Rendering: Lock Branch for non-admins */}
              {isBranchLocked ? (
                <div className="bg-slate-900 text-white border border-slate-800 rounded-xl px-5 py-2.5 flex items-center gap-3 shadow-xl">
                  <Lock size={14} className="text-blue-400" />
                  <span className="text-[10px] font-black uppercase tracking-[0.2em]">{selectedDept} Ledger Slice</span>
                </div>
              ) : (
                <div className="bg-white border border-slate-200 rounded-xl px-4 py-2.5 flex items-center gap-2 shadow-sm">
                  <Building2 size={16} className="text-slate-400" />
                  <select value={selectedDept} onChange={(e) => setSelectedDept(e.target.value as Department)} className="text-sm font-bold bg-transparent border-none outline-none text-slate-700 cursor-pointer">
                    {DEPARTMENTS.map(d => <option key={d} value={d}>{d}</option>)}
                  </select>
                </div>
              )}

              <div className="bg-white border border-slate-200 rounded-xl px-4 py-2.5 flex items-center gap-2 shadow-sm">
                <CalendarDays size={16} className="text-slate-400" />
                <select value={selectedSem} onChange={(e) => setSelectedSem(e.target.value as Semester)} className="text-sm font-bold bg-transparent border-none outline-none text-slate-700 cursor-pointer">
                  {SEMESTERS.map(s => <option key={s} value={s}>SEM: {s}</option>)}
                </select>
              </div>
            </div>
            <div className="flex gap-2">
              <button onClick={() => window.print()} className="flex items-center gap-2 px-8 py-3 bg-slate-900 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl active:scale-95 transition-all"><Printer size={16} /> Print Report</button>
            </div>
          </div>

          <div className="bg-white p-12 md:p-16 border border-slate-200 shadow-2xl rounded-[4rem] relative overflow-hidden print:p-0 print:border-none print:shadow-none w-full">
            <div className="relative z-10 space-y-16">
              <div className="text-center space-y-6 border-b-2 border-slate-900 pb-12">
                  <div className="w-24 h-24 bg-slate-900 text-white rounded-[2rem] flex items-center justify-center mx-auto font-black text-3xl mb-4 shadow-2xl">SRK</div>
                  <h1 className="text-3xl font-black text-slate-900 tracking-tighter uppercase leading-tight">SRK INSTITUTE OF TECHNOLOGY</h1>
                  <p className="text-[11px] text-slate-500 uppercase tracking-[0.4em] font-black">Blockchain-Verified Faculty Assessment Report</p>
                  <div className="h-1 w-20 bg-blue-600 mx-auto rounded-full"></div>
                  <h2 className="text-xl font-black text-slate-900 mt-6 pt-6 border-t border-slate-100 uppercase tracking-tight">Academic Unit: {selectedDept}</h2>
              </div>

              <div className="border-[3px] border-slate-900 rounded-[2rem] overflow-hidden">
                <table className="w-full border-collapse">
                  <thead>
                    <tr className="bg-slate-50 border-b-[3px] border-slate-900">
                      <th className="p-6 text-center border-r-[3px] border-slate-900 font-black text-slate-900 w-20 text-xs">S.NO</th>
                      <th className="p-6 text-left border-r-[3px] border-slate-900 font-black text-slate-900 text-xs uppercase tracking-wider">Faculty Node</th>
                      <th className="p-6 text-left border-r-[3px] border-slate-900 font-black text-slate-900 text-xs uppercase tracking-wider">Subject Code/Title</th>
                      <th className="p-6 text-center font-black text-slate-900 text-xs uppercase tracking-wider">Score (20)</th>
                    </tr>
                  </thead>
                  <tbody className="text-slate-800 font-bold">
                    {reportData.map((row, index) => (
                      <tr key={index} className="border-b-[3px] border-slate-900 last:border-b-0 hover:bg-slate-50/50 transition-colors">
                        <td className="p-6 text-center border-r-[3px] border-slate-900 font-mono">{index + 1}</td>
                        <td className="p-6 border-r-[3px] border-slate-900">{row!.faculty}</td>
                        <td className="p-6 border-r-[3px] border-slate-900 text-sm">{row!.subject}</td>
                        <td className="p-6 text-center font-black text-blue-700 text-lg">{row!.points.toFixed(2)}</td>
                      </tr>
                    ))}
                    {reportData.length === 0 && (
                      <tr><td colSpan={4} className="p-20 text-center text-slate-300 font-black uppercase text-[10px] tracking-widest">No Verified Ledger Data Found for this Semester Node</td></tr>
                    )}
                  </tbody>
                </table>
              </div>

              <div className="pt-24 flex justify-between items-end">
                <div className="text-left space-y-2">
                  <div className="flex items-center gap-2 text-emerald-600 font-black text-[10px] uppercase">
