                    {reportData.map((row, index) => (
                      <tr key={index} className="border-b-[4px] border-slate-900 last:border-b-0 hover:bg-slate-50 transition-colors">
                        <td className="p-8 text-center border-r-[4px] border-slate-900 font-mono text-lg">{index + 1}</td>
                        <td className="p-8 border-r-[4px] border-slate-900">
                           <div className="flex flex-col">
                              <span className="text-lg font-black">{row!.faculty}</span>
                              <span className="text-[10px] uppercase font-black text-slate-400 tracking-widest">{row!.facultyId}</span>
                           </div>
                        </td>
                        <td className="p-8 border-r-[4px] border-slate-900 text-md uppercase font-black text-slate-600">{row!.subject}</td>
                        <td className="p-8 text-center">
                           <span className={`text-2xl font-black px-6 py-2 rounded-2xl ${row!.points >= 18 ? 'text-emerald-600 bg-emerald-50' : 'text-blue-700 bg-blue-50'}`}>
                              {row!.points.toFixed(2)}
