                        </td>
                      </tr>
                    ))}
                    {reportData.length === 0 && (
                      <tr><td colSpan={4} className="p-32 text-center text-slate-300 font-black uppercase text-xs tracking-widest">Registry Void: No Verified Assessment Nodes Found for this Semester</td></tr>
