              <div className="pt-32 flex justify-between items-end px-4">
                <div className="text-left space-y-3">
                  <div className="flex items-center gap-3 text-emerald-600 font-black text-[11px] uppercase tracking-widest">
                    <CheckCircle2 size={20} /> Integrity Verified by SRK-Ledger
                  </div>
                  <p className="text-[10px] text-slate-400 font-bold max-w-sm leading-relaxed">This departmental audit is cryptographically derived. Modification of rating indices is prohibited by institutional ledger constraints.</p>
