      <style dangerouslySetInnerHTML={{ __html: `@media print { .no-print { display: none !important; } main { padding: 0 !important; } .rounded-[5rem] { border-radius: 0 !important; } body { background: white !important; } }` }} />
    </div>
  );
};

export default AnalysisView;
